"use strict";(globalThis.webpackChunkpaimon_docs=globalThis.webpackChunkpaimon_docs||[]).push([[2024],{917(t,e,n){n.r(e),n.d(e,{assets:()=>l,contentTitle:()=>s,default:()=>p,frontMatter:()=>i,metadata:()=>r,toc:()=>h});const r=JSON.parse('{"id":"maintenance/configurations","title":"Configurations","description":"\x3c!--","source":"@site/docs/maintenance/configurations.mdx","sourceDirName":"maintenance","slug":"/maintenance/configurations","permalink":"/docs/master/maintenance/configurations","draft":false,"unlisted":false,"editUrl":"https://github.com/apache/paimon/edit/master/docs/docs/maintenance/configurations.mdx","tags":[],"version":"current","sidebarPosition":100,"frontMatter":{"title":"Configurations","sidebar_position":100},"sidebar":"docs","previous":{"title":"Manage Partitions","permalink":"/docs/master/maintenance/manage-partitions"},"next":{"title":"Program API","permalink":"/docs/master/program-api/"}}');var d=n(4848),a=n(8453),o=n(6678);const i={title:"Configurations",sidebar_position:100},s="Configuration",l={},h=[{value:"CoreOptions",id:"coreoptions",level:3},{value:"CatalogOptions",id:"catalogoptions",level:3},{value:"HiveCatalogOptions",id:"hivecatalogoptions",level:3},{value:"HiveConnectorOptions",id:"hiveconnectoroptions",level:3},{value:"JdbcCatalogOptions",id:"jdbccatalogoptions",level:3},{value:"FlinkCatalogOptions",id:"flinkcatalogoptions",level:3},{value:"FlinkConnectorOptions",id:"flinkconnectoroptions",level:3},{value:"SparkCatalogOptions",id:"sparkcatalogoptions",level:3},{value:"SparkConnectorOptions",id:"sparkconnectoroptions",level:3},{value:"ORC Options",id:"orc-options",level:3},{value:"RocksDB Options",id:"rocksdb-options",level:3}];function c(t){const e={h1:"h1",h3:"h3",header:"header",p:"p",...(0,a.R)(),...t.components};return(0,d.jsxs)(d.Fragment,{children:[(0,d.jsx)(e.header,{children:(0,d.jsx)(e.h1,{id:"configuration",children:"Configuration"})}),"\n",(0,d.jsx)(e.h3,{id:"coreoptions",children:"CoreOptions"}),"\n",(0,d.jsx)(e.p,{children:"Core options for paimon."}),"\n",(0,d.jsx)(o.A,{html:'\x3c!--\nLicensed to the Apache Software Foundation (ASF) under one\nor more contributor license agreements.  See the NOTICE file\ndistributed with this work for additional information\nregarding copyright ownership.  The ASF licenses this file\nto you under the Apache License, Version 2.0 (the\n"License"); you may not use this file except in compliance\nwith the License.  You may obtain a copy of the License at\n\n  http://www.apache.org/licenses/LICENSE-2.0\n\nUnless required by applicable law or agreed to in writing,\nsoftware distributed under the License is distributed on an\n"AS IS" BASIS, WITHOUT WARRANTIES OR CONDITIONS OF ANY\nKIND, either express or implied.  See the License for the\nspecific language governing permissions and limitations\nunder the License.\n--\x3e\n<table class="configuration table table-bordered">\n    <thead>\n        <tr>\n            <th class="text-left" style="width: 20%">Key</th>\n            <th class="text-left" style="width: 15%">Default</th>\n            <th class="text-left" style="width: 10%">Type</th>\n            <th class="text-left" style="width: 55%">Description</th>\n        </tr>\n    </thead>\n    <tbody>\n        <tr>\n            <td><h5>add-column-before-partition</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>If true, when adding a new column without specifying a position, the column will be placed before the first partition column instead of at the end of the schema. This only takes effect for partitioned tables.</td>\n        </tr>\n        <tr>\n            <td><h5>aggregation.remove-record-on-delete</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether to remove the whole row in aggregation engine when -D records are received.</td>\n        </tr>\n        <tr>\n            <td><h5>alter-column-null-to-not-null.disabled</h5></td>\n            <td style="word-wrap: break-word;">true</td>\n            <td>Boolean</td>\n            <td>If true, it disables altering column type from null to not null. Default is true. Users can disable this option to explicitly convert null column type to not null.</td>\n        </tr>\n        <tr>\n            <td><h5>async-file-write</h5></td>\n            <td style="word-wrap: break-word;">true</td>\n            <td>Boolean</td>\n            <td>Whether to enable asynchronous IO writing when writing files.</td>\n        </tr>\n        <tr>\n            <td><h5>auto-create</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether to create underlying storage when reading and writing the table.</td>\n        </tr>\n        <tr>\n            <td><h5>blob-as-descriptor</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Write blob field using blob descriptor rather than blob bytes.</td>\n        </tr>\n        <tr>\n            <td><h5>blob-compaction.enabled</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether to compact blob files when compacting a data evolution table.</td>\n        </tr>\n        <tr>\n            <td><h5>blob-descriptor-field</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>Comma-separated field names to treat as BLOB fields and store as serialized BlobDescriptor bytes inline in data files.</td>\n        </tr>\n        <tr>\n            <td><h5>blob-descriptor.source-table</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>The source table whose FileIO is used to read descriptor-backed BLOB content and copy it into the target table\'s managed BLOB storage. The table must belong to the current catalog and can include a branch suffix, for example db.table$branch_rt. This option is not supported for target tables without a catalog loader, including external tables in REST catalogs. When set, other blob-descriptor.* FileIO options are ignored.</td>\n        </tr>\n        <tr>\n            <td><h5>blob-field</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>Specifies column names that should be stored as blob type. This is used when you want to treat a BYTES column as a BLOB. Fields listed in blob-descriptor-field or blob-view-field are also treated as BLOB fields.</td>\n        </tr>\n        <tr>\n            <td><h5>blob-view-field</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>Comma-separated field names to treat as BLOB fields and store as serialized BlobViewStruct bytes inline in data files and resolve from upstream tables at read time.</td>\n        </tr>\n        <tr>\n            <td><h5>blob-view.resolve.enabled</h5></td>\n            <td style="word-wrap: break-word;">true</td>\n            <td>Boolean</td>\n            <td>Whether to resolve blob-view-field values from upstream tables at read time. Set to false to preserve BlobViewStruct references when forwarding blob view values to another blob-view table.</td>\n        </tr>\n        <tr>\n            <td><h5>blob-write-null-on-fetch-failure</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether to write NULL for a descriptor BLOB value when the referenced resource cannot be fetched during Flink writes (e.g. invalid URI or HTTP errors other than 404). HTTP 404 is handled by \'blob-write-null-on-missing-file\'. When false, the write fails when the descriptor is read.</td>\n        </tr>\n        <tr>\n            <td><h5>blob-write-null-on-missing-file</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether to write NULL for a descriptor BLOB value when the referenced file or HTTP resource does not exist during Flink writes. When false, the write fails when the descriptor is read.</td>\n        </tr>\n        <tr>\n            <td><h5>blob.copy-buffer-size</h5></td>\n            <td style="word-wrap: break-word;">4 kb</td>\n            <td>MemorySize</td>\n            <td>Buffer size used when copying BLOB payloads into BLOB files.</td>\n        </tr>\n        <tr>\n            <td><h5>blob.split-by-file-size</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Boolean</td>\n            <td>Whether to consider blob file size as a factor when performing scan splitting.</td>\n        </tr>\n        <tr>\n            <td><h5>blob.target-file-size</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>MemorySize</td>\n            <td>Target size of a blob file. Default is value of TARGET_FILE_SIZE.</td>\n        </tr>\n        <tr>\n            <td><h5>bucket</h5></td>\n            <td style="word-wrap: break-word;">-1</td>\n            <td>Integer</td>\n            <td>Bucket number for file store.<br />It should either be equal to -1 (dynamic bucket mode), -2 (postpone bucket mode), or it must be greater than 0 (fixed bucket mode).</td>\n        </tr>\n        <tr>\n            <td><h5>bucket-append-ordered</h5></td>\n            <td style="word-wrap: break-word;">true</td>\n            <td>Boolean</td>\n            <td>Whether to ignore the order of the buckets when reading data from an append-only table.</td>\n        </tr>\n        <tr>\n            <td><h5>bucket-function.type</h5></td>\n            <td style="word-wrap: break-word;">default</td>\n            <td><p>Enum</p></td>\n            <td>The bucket function for paimon bucket.<br /><br />Possible values:<ul><li>"default": The default bucket function which will use arithmetic: bucket_id = Math.abs(hash_bucket_binary_row % numBuckets) to get bucket.</li><li>"mod": The modulus bucket function which will use modulus arithmetic: bucket_id = Math.floorMod(bucket_key_value, numBuckets) to get bucket. Note: the bucket key must be a single field of INT or BIGINT datatype.</li><li>"hive": The hive bucket function which will use hive-compatible hash arithmetic to get bucket.</li></ul></td>\n        </tr>\n        <tr>\n            <td><h5>bucket-key</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>Specify the paimon distribution policy. Data is assigned to each bucket according to the hash value of bucket-key.<br />If you specify multiple fields, delimiter is \',\'.<br />If not specified, the primary key will be used; if there is no primary key, the full row will be used.</td>\n        </tr>\n        <tr>\n            <td><h5>cache-page-size</h5></td>\n            <td style="word-wrap: break-word;">64 kb</td>\n            <td>MemorySize</td>\n            <td>Memory page size for caching.</td>\n        </tr>\n        <tr>\n            <td><h5>chain-table.chain-partition-keys</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>Partition keys that participate in chain logic. Must be a contiguous suffix of the table\'s partition keys. Comma-separated. If not set, all partition keys participate in chain.</td>\n        </tr>\n        <tr>\n            <td><h5>chain-table.enabled</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether enabled chain table.</td>\n        </tr>\n        <tr>\n            <td><h5>chain-table.streaming.merge-snapshot</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>If true, the starting phase of chain table streaming read performs anchor-based chain merging: for each group it merges the latest snapshot partition with delta partitions whose chain key is strictly greater than the snapshot chain key. This allows streaming readers to see cross-branch deletions and updates at the cost of a heavier startup scan. When false (default), the starting phase only reads the latest snapshot partition per group and later delta partitions as separate splits, which is lightweight but may not reflect cross-branch deletes.</td>\n        </tr>\n        <tr>\n            <td><h5>changelog-file.compression</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>Changelog file compression.</td>\n        </tr>\n        <tr>\n            <td><h5>changelog-file.format</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>Specify the message format of changelog files, currently parquet, avro and orc are supported.</td>\n        </tr>\n        <tr>\n            <td><h5>changelog-file.prefix</h5></td>\n            <td style="word-wrap: break-word;">"changelog-"</td>\n            <td>String</td>\n            <td>Specify the file name prefix of changelog files.</td>\n        </tr>\n        <tr>\n            <td><h5>changelog-file.stats-mode</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>Changelog file metadata stats collection. none, counts, truncate(16), full is available.</td>\n        </tr>\n        <tr>\n            <td><h5>changelog-producer</h5></td>\n            <td style="word-wrap: break-word;">none</td>\n            <td><p>Enum</p></td>\n            <td>Whether to double write to a changelog file. This changelog file keeps the details of data changes, it can be read directly during stream reads. This can be applied to tables with primary keys. <br /><br />Possible values:<ul><li>"none": No changelog file.</li><li>"input": Double write to a changelog file when flushing memory table, the changelog is from input.</li><li>"full-compaction": Generate changelog files with each full compaction.</li><li>"lookup": Generate changelog files through \'lookup\' compaction.</li></ul></td>\n        </tr>\n        <tr>\n            <td><h5>changelog-producer.row-deduplicate</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether to generate -U, +U changelog for the same record. This configuration is only valid for the changelog-producer is lookup or full-compaction.</td>\n        </tr>\n        <tr>\n            <td><h5>changelog-producer.row-deduplicate-ignore-fields</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>Fields that are ignored for comparison while generating -U, +U changelog for the same record. This configuration is only valid for the changelog-producer.row-deduplicate is true.</td>\n        </tr>\n        <tr>\n            <td><h5>changelog.num-retained.max</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Integer</td>\n            <td>The maximum number of completed changelog to retain. Should be greater than or equal to the minimum number.</td>\n        </tr>\n        <tr>\n            <td><h5>changelog.num-retained.min</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Integer</td>\n            <td>The minimum number of completed changelog to retain. Should be greater than or equal to 1.</td>\n        </tr>\n        <tr>\n            <td><h5>changelog.time-retained</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Duration</td>\n            <td>The maximum time of completed changelog to retain.</td>\n        </tr>\n        <tr>\n            <td><h5>clustering.columns</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>Specifies the column name(s) used for comparison during range partitioning, in the format \'columnName1,columnName2\'. If not set or set to an empty string, it indicates that the range partitioning feature is not enabled. This option will be effective only for append table without primary keys and batch execution mode.</td>\n        </tr>\n        <tr>\n            <td><h5>clustering.history-partition.idle-to-full-sort</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Duration</td>\n            <td>The duration after which a partition without new updates is considered a historical partition. Historical partitions will be automatically fully clustered during the cluster operation.</td>\n        </tr>\n        <tr>\n            <td><h5>clustering.history-partition.limit</h5></td>\n            <td style="word-wrap: break-word;">5</td>\n            <td>Integer</td>\n            <td>The limit of history partition number for automatically performing full clustering.</td>\n        </tr>\n        <tr>\n            <td><h5>clustering.incremental</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether enable incremental clustering.</td>\n        </tr>\n        <tr>\n            <td><h5>clustering.incremental.mode</h5></td>\n            <td style="word-wrap: break-word;">global-sort</td>\n            <td><p>Enum</p></td>\n            <td>The sort mode for incremental clustering compaction. \'global-sort\' (default) performs a global range shuffle so output files are globally ordered. \'local-sort\' skips the global shuffle and only sorts rows within each compaction task, producing files that are internally ordered. \'local-sort\' is cheaper and sufficient for Parquet lookup optimizations.<br /><br />Possible values:<ul><li>"global-sort": Perform global range shuffle and then local sort. Output files are globally ordered but require network shuffling.</li><li>"local-sort": Sort rows only within each compaction task without global shuffle. Every output file is internally ordered.</li></ul></td>\n        </tr>\n        <tr>\n            <td><h5>clustering.incremental.optimize-write</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether enable perform clustering before write phase when incremental clustering is enabled.</td>\n        </tr>\n        <tr>\n            <td><h5>clustering.strategy</h5></td>\n            <td style="word-wrap: break-word;">"auto"</td>\n            <td>String</td>\n            <td>Specifies the comparison algorithm used for range partitioning, including \'zorder\', \'hilbert\', and \'order\', corresponding to the z-order curve algorithm, hilbert curve algorithm, and basic type comparison algorithm, respectively. When not configured, it will automatically determine the algorithm based on the number of columns in \'clustering.by-columns\'. \'order\' is used for 1 column, \'zorder\' for less than 5 columns, and \'hilbert\' for 5 or more columns.</td>\n        </tr>\n        <tr>\n            <td><h5>commit.callback.#.param</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>Parameter string for the constructor of class #. Callback class should parse the parameter by itself.</td>\n        </tr>\n        <tr>\n            <td><h5>commit.callbacks</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>A list of commit callback classes to be called after a successful commit. Class names are connected with comma (example: com.test.CallbackA,com.sample.CallbackB).</td>\n        </tr>\n        <tr>\n            <td><h5>commit.discard-duplicate-files</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether discard duplicate files in commit.</td>\n        </tr>\n        <tr>\n            <td><h5>commit.force-compact</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether to force a compaction before commit.</td>\n        </tr>\n        <tr>\n            <td><h5>commit.force-create-snapshot</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>In streaming job, whether to force creating snapshot when there is no data in this write-commit phase.</td>\n        </tr>\n        <tr>\n            <td><h5>commit.max-retries</h5></td>\n            <td style="word-wrap: break-word;">10</td>\n            <td>Integer</td>\n            <td>Maximum number of retries when commit failed.</td>\n        </tr>\n        <tr>\n            <td><h5>commit.max-retry-wait</h5></td>\n            <td style="word-wrap: break-word;">10 s</td>\n            <td>Duration</td>\n            <td>Max retry wait time when commit failed.</td>\n        </tr>\n        <tr>\n            <td><h5>commit.min-retry-wait</h5></td>\n            <td style="word-wrap: break-word;">10 ms</td>\n            <td>Duration</td>\n            <td>Min retry wait time when commit failed.</td>\n        </tr>\n        <tr>\n            <td><h5>commit.strict-mode.last-safe-snapshot</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Long</td>\n            <td>If set, committer will check if there are other commit user\'s snapshot starting from the snapshot after this one. If found a COMPACT / OVERWRITE snapshot, or found a APPEND snapshot which committed files to fixed bucket, commit will be aborted.If the value of this option is -1, committer will not check for its first commit.</td>\n        </tr>\n        <tr>\n            <td><h5>commit.timeout</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Duration</td>\n            <td>Timeout duration of retry when commit failed.</td>\n        </tr>\n        <tr>\n            <td><h5>commit.user-prefix</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>Specifies the commit user prefix.</td>\n        </tr>\n        <tr>\n            <td><h5>compaction.delete-ratio-threshold</h5></td>\n            <td style="word-wrap: break-word;">0.2</td>\n            <td>Double</td>\n            <td>Ratio of the deleted rows in a data file to be forced compacted for append-only table.</td>\n        </tr>\n        <tr>\n            <td><h5>compaction.file-num-limit</h5></td>\n            <td style="word-wrap: break-word;">100000</td>\n            <td>Integer</td>\n            <td>To avoid OOM caused by scanning compaction files, you can use this option to limit the for unaware-bucket append table compaction.</td>\n        </tr>\n        <tr>\n            <td><h5>compaction.force-rewrite-all-files</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether to force pick all files for a full compaction. Usually seen in a compaction task to external paths.</td>\n        </tr>\n        <tr>\n            <td><h5>compaction.force-up-level-0</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>If set to true, compaction strategy will always include all level 0 files in candidates.</td>\n        </tr>\n        <tr>\n            <td><h5>compaction.incremental-size-threshold</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>MemorySize</td>\n            <td>When incremental size is bigger than this threshold, force a full compaction.</td>\n        </tr>\n        <tr>\n            <td><h5>compaction.max-size-amplification-percent</h5></td>\n            <td style="word-wrap: break-word;">200</td>\n            <td>Integer</td>\n            <td>The size amplification is defined as the amount (in percentage) of additional storage needed to store a single byte of data in the merge tree for changelog mode table.</td>\n        </tr>\n        <tr>\n            <td><h5>compaction.min.file-num</h5></td>\n            <td style="word-wrap: break-word;">5</td>\n            <td>Integer</td>\n            <td>For file set [f_0,...,f_N], the minimum file number to trigger a compaction for append-only table.</td>\n        </tr>\n        <tr>\n            <td><h5>compaction.offpeak-ratio</h5></td>\n            <td style="word-wrap: break-word;">0</td>\n            <td>Integer</td>\n            <td>Allows you to set a different (by default, more aggressive) percentage ratio for determining  whether larger sorted run\'s size are included in compactions during off-peak hours. Works in the  same way as compaction.size-ratio. Only applies if offpeak.start.hour and  offpeak.end.hour are also enabled. <br /> For instance, if your cluster experiences low pressure between 2 AM  and 6 PM ,  you can configure `compaction.offpeak.start.hour=2` and `compaction.offpeak.end.hour=18` to define this period as off-peak hours.  During these hours, you can increase the off-peak compaction ratio (e.g. `compaction.offpeak-ratio=20`) to enable more aggressive data compaction</td>\n        </tr>\n        <tr>\n            <td><h5>compaction.offpeak.end.hour</h5></td>\n            <td style="word-wrap: break-word;">-1</td>\n            <td>Integer</td>\n            <td>The end of off-peak hours, expressed as an integer between 0 and 23, exclusive. Set to -1 to disable off-peak.</td>\n        </tr>\n        <tr>\n            <td><h5>compaction.offpeak.start.hour</h5></td>\n            <td style="word-wrap: break-word;">-1</td>\n            <td>Integer</td>\n            <td>The start of off-peak hours, expressed as an integer between 0 and 23, inclusive Set to -1 to disable off-peak</td>\n        </tr>\n        <tr>\n            <td><h5>compaction.optimization-interval</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Duration</td>\n            <td>Implying how often to perform an optimization compaction, this configuration is used to ensure the query timeliness of the read-optimized system table.</td>\n        </tr>\n        <tr>\n            <td><h5>compaction.size-ratio</h5></td>\n            <td style="word-wrap: break-word;">1</td>\n            <td>Integer</td>\n            <td>Percentage flexibility while comparing sorted run size for changelog mode table. If the candidate sorted run(s) size is 1% smaller than the next sorted run\'s size, then include next sorted run into this candidate set.</td>\n        </tr>\n        <tr>\n            <td><h5>compaction.skip-expired-partitions</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether to skip compacting partitions that are already expired according to \'partition.expiration-time\'. Only effective when \'partition.expiration-time\' is set and \'partition.expiration-strategy\' is \'values-time\'. Note: even when this option is enabled, expired partitions may still be deleted during the compaction commit phase as a side effect of partition expiration triggered by committing the remaining active partitions.</td>\n        </tr>\n        <tr>\n            <td><h5>compaction.small-file-ratio</h5></td>\n            <td style="word-wrap: break-word;">0.7</td>\n            <td>Double</td>\n            <td>The ratio of target file size. Files whose size is smaller than target-file-size * compaction.small-file-ratio will be picked for compaction rewriting. This avoids compacting the same file repeatedly due to compression inaccuracy causing output files to be slightly smaller than the target size.</td>\n        </tr>\n        <tr>\n            <td><h5>compaction.total-size-threshold</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>MemorySize</td>\n            <td>When total size is smaller than this threshold, force a full compaction.</td>\n        </tr>\n        <tr>\n            <td><h5>consumer-id</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>Consumer id for recording the offset of consumption in the storage.</td>\n        </tr>\n        <tr>\n            <td><h5>consumer.changelog-only</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>If true, consumer will only affect changelog expiration and will not prevent snapshot from being expired.</td>\n        </tr>\n        <tr>\n            <td><h5>consumer.expiration-time</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Duration</td>\n            <td>The expiration interval of consumer files. A consumer file will be expired if it\'s lifetime after last modification is over this value.</td>\n        </tr>\n        <tr>\n            <td><h5>consumer.ignore-progress</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether to ignore consumer progress for the newly started job.</td>\n        </tr>\n        <tr>\n            <td><h5>consumer.mode</h5></td>\n            <td style="word-wrap: break-word;">exactly-once</td>\n            <td><p>Enum</p></td>\n            <td>Specify the consumer consistency mode for table.<br /><br />Possible values:<ul><li>"exactly-once": Readers consume data at snapshot granularity, and strictly ensure that the snapshot-id recorded in the consumer is the snapshot-id + 1 that all readers have exactly consumed.</li><li>"at-least-once": Each reader consumes snapshots at a different rate, and the snapshot with the slowest consumption progress among all readers will be recorded in the consumer.</li></ul></td>\n        </tr>\n        <tr>\n            <td><h5>continuous.discovery-interval</h5></td>\n            <td style="word-wrap: break-word;">10 s</td>\n            <td>Duration</td>\n            <td>The discovery interval of continuous reading.</td>\n        </tr>\n        <tr>\n            <td><h5>cross-partition-upsert.bootstrap-parallelism</h5></td>\n            <td style="word-wrap: break-word;">10</td>\n            <td>Integer</td>\n            <td>The parallelism for bootstrap in a single task for cross partition upsert.</td>\n        </tr>\n        <tr>\n            <td><h5>cross-partition-upsert.index-ttl</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Duration</td>\n            <td>The TTL in rocksdb index for cross partition upsert (primary keys not contain all partition fields), this can avoid maintaining too many indexes and lead to worse and worse performance, but please note that this may also cause data duplication.</td>\n        </tr>\n        <tr>\n            <td><h5>data-evolution.compaction.rewrite-row-ids</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether data-evolution compaction may rewrite row IDs while physically applying deletion vectors. Enable only when callers do not rely on stable _ROW_ID; this invalidates row-id based references and drops global indexes for affected partitions.</td>\n        </tr>\n        <tr>\n            <td><h5>data-evolution.enabled</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether enable data evolution for row tracking table.</td>\n        </tr>\n        <tr>\n            <td><h5>data-evolution.merge-into.file-pruning</h5></td>\n            <td style="word-wrap: break-word;">true</td>\n            <td>Boolean</td>\n            <td>If true, enables the file-level pruning step for MergeInto partial column update on data-evolution tables. Set this to false when most files in the target partition are expected to be updated, so that the overhead of collecting touched file IDs outweighs the benefit of pruning untouched files.</td>\n        </tr>\n        <tr>\n            <td><h5>data-evolution.merge-into.source-persist</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether to persist source when process merge into action on data evolution table.</td>\n        </tr>\n        <tr>\n            <td><h5>data-evolution.row-sidecar.enabled</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether to generate row-store sidecar files for normal data files on data evolution tables. The sidecar files are used to accelerate sparse row-id reads.</td>\n        </tr>\n        <tr>\n            <td><h5>data-evolution.row-sidecar.max-selected-rows</h5></td>\n            <td style="word-wrap: break-word;">4096</td>\n            <td>Long</td>\n            <td>Maximum selected row count for reading a row-store sidecar file. The sidecar is used only when the selected rows are no more than this value and the selected row ratio is no more than data-evolution.row-sidecar.max-selection-ratio.</td>\n        </tr>\n        <tr>\n            <td><h5>data-evolution.row-sidecar.max-selection-ratio</h5></td>\n            <td style="word-wrap: break-word;">0.05</td>\n            <td>Double</td>\n            <td>Maximum selected row ratio for reading a row-store sidecar file. The value must be in (0, 1]. The sidecar is used only when the selected row ratio is no more than this value and the selected row count is no more than data-evolution.row-sidecar.max-selected-rows.</td>\n        </tr>\n        <tr>\n            <td><h5>data-file.external-paths</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>The external paths where the data of this table will be written, multiple elements separated by commas.</td>\n        </tr>\n        <tr>\n            <td><h5>data-file.external-paths.specific-fs</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>The specific file system of the external path when data-file.external-paths.strategy is set to specific-fs, should be the prefix scheme of the external path, now supported are s3 and oss.</td>\n        </tr>\n        <tr>\n            <td><h5>data-file.external-paths.strategy</h5></td>\n            <td style="word-wrap: break-word;">none</td>\n            <td><p>Enum</p></td>\n            <td>The strategy of selecting an external path when writing data.<br /><br />Possible values:<ul><li>"none": Do not choose any external storage, data will still be written to the default warehouse path.</li><li>"specific-fs": Select a specific file system as the external path. Currently supported are S3 and OSS.</li><li>"round-robin": When writing a new file, a path is chosen from data-file.external-paths in turn.</li><li>"entropy-inject": When writing a new file, a path is chosen based on the hash value of the file\'s content.</li><li>"weight-robin": When writing a new file, a path is chosen based on configured weights.</li></ul></td>\n        </tr>\n        <tr>\n            <td><h5>data-file.external-paths.weights</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>The weights for external paths when data-file.external-paths.strategy is set to weight-robin. Format: \'weight1,weight2,...\' with weights corresponding to paths in data-file.external-paths by order. Example: \'10,5,15\' means first path has weight 10, second 5, third 15. Weights must be positive integers.</td>\n        </tr>\n        <tr>\n            <td><h5>data-file.path-directory</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>Specify the path directory of data files.</td>\n        </tr>\n        <tr>\n            <td><h5>data-file.prefix</h5></td>\n            <td style="word-wrap: break-word;">"data-"</td>\n            <td>String</td>\n            <td>Specify the file name prefix of data files.</td>\n        </tr>\n        <tr>\n            <td><h5>data-file.thin-mode</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Enable data file thin mode to avoid duplicate columns storage.</td>\n        </tr>\n        <tr>\n            <td><h5>delete.force-produce-changelog</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Force produce changelog in delete sql, or you can use \'streaming-read-overwrite\' to read changelog from overwrite commit.</td>\n        </tr>\n        <tr>\n            <td><h5>deletion-vector.index-file.target-size</h5></td>\n            <td style="word-wrap: break-word;">2 mb</td>\n            <td>MemorySize</td>\n            <td>The target size of deletion vector index file.</td>\n        </tr>\n        <tr>\n            <td><h5>deletion-vectors.bitmap64</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Enable 64 bit bitmap implementation. Note that only 64 bit bitmap implementation is compatible with Iceberg.</td>\n        </tr>\n        <tr>\n            <td><h5>deletion-vectors.enabled</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether to enable deletion vectors mode. In this mode, index files containing deletion vectors are generated when data is written, which marks the data for deletion. During read operations, by applying these index files, merging can be avoided.</td>\n        </tr>\n        <tr>\n            <td><h5>deletion-vectors.merge-on-read</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>When deletion vectors are enabled, uncompacted files are not visible by default. Set this to true to enable merge-on-read, which makes uncompacted data visible at the cost of read performance. This option only affects batch scan visibility of DV level-0 files, it does not change streaming scan or changelog behavior.</td>\n        </tr>\n        <tr>\n            <td><h5>deletion-vectors.modifiable</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether to enable modifying deletion vectors mode.</td>\n        </tr>\n        <tr>\n            <td><h5>disable-explicit-type-casting</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>If true, it disables explicit type casting. For ex: it disables converting LONG type to INT type. Users can enable this option to disable explicit type casting</td>\n        </tr>\n        <tr>\n            <td><h5>dynamic-bucket.assigner-parallelism</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Integer</td>\n            <td>Parallelism of assigner operator for dynamic bucket mode, it is related to the number of initialized bucket, too small will lead to insufficient processing speed of assigner.</td>\n        </tr>\n        <tr>\n            <td><h5>dynamic-bucket.initial-buckets</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Integer</td>\n            <td>Initial buckets for a partition in assigner operator for dynamic bucket mode.</td>\n        </tr>\n        <tr>\n            <td><h5>dynamic-bucket.max-buckets</h5></td>\n            <td style="word-wrap: break-word;">-1</td>\n            <td>Integer</td>\n            <td>Max buckets for a partition in dynamic bucket mode, It should either be equal to -1 (unlimited), or it must be greater than 0 (fixed upper bound).</td>\n        </tr>\n        <tr>\n            <td><h5>dynamic-bucket.target-row-num</h5></td>\n            <td style="word-wrap: break-word;">2000000</td>\n            <td>Long</td>\n            <td>If the bucket is -1, for primary key table, is dynamic bucket mode, this option controls the target row number for one bucket.</td>\n        </tr>\n        <tr>\n            <td><h5>dynamic-partition-overwrite</h5></td>\n            <td style="word-wrap: break-word;">true</td>\n            <td>Boolean</td>\n            <td>Whether only overwrite dynamic partition when overwriting a partitioned table with dynamic partition columns. Works only when the table has partition keys.</td>\n        </tr>\n        <tr>\n            <td><h5>end-input.check-partition-expire</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Optional endInput check partition expire used in case of batch mode or bounded stream.</td>\n        </tr>\n        <tr>\n            <td><h5>fields.default-aggregate-function</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>Default aggregate function of all fields for partial-update and aggregate merge function.</td>\n        </tr>\n        <tr>\n            <td><h5>file-index.in-manifest-threshold</h5></td>\n            <td style="word-wrap: break-word;">500 bytes</td>\n            <td>MemorySize</td>\n            <td>The threshold to store file index bytes in manifest.</td>\n        </tr>\n        <tr>\n            <td><h5>file-index.read.enabled</h5></td>\n            <td style="word-wrap: break-word;">true</td>\n            <td>Boolean</td>\n            <td>Whether enabled read file index.</td>\n        </tr>\n        <tr>\n            <td><h5>file-operation.thread-num</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Integer</td>\n            <td>The maximum number of concurrent file operations. By default is the number of processors available to the Java virtual machine.</td>\n        </tr>\n        <tr>\n            <td><h5>file-reader-async-threshold</h5></td>\n            <td style="word-wrap: break-word;">10 mb</td>\n            <td>MemorySize</td>\n            <td>The threshold for read file async.</td>\n        </tr>\n        <tr>\n            <td><h5>file.block-size</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>MemorySize</td>\n            <td>File block size of format, default value of orc stripe is 64 MB, and parquet row group is 128 MB.</td>\n        </tr>\n        <tr>\n            <td><h5>file.compression</h5></td>\n            <td style="word-wrap: break-word;">"zstd"</td>\n            <td>String</td>\n            <td>Default file compression. For faster read and write, it is recommended to use zstd.</td>\n        </tr>\n        <tr>\n            <td><h5>file.compression.per.level</h5></td>\n            <td style="word-wrap: break-word;"></td>\n            <td>Map</td>\n            <td>Define different compression policies for different level, you can add the conf like this: \'file.compression.per.level\' = \'0:lz4,1:zstd\'.</td>\n        </tr>\n        <tr>\n            <td><h5>file.compression.zstd-level</h5></td>\n            <td style="word-wrap: break-word;">1</td>\n            <td>Integer</td>\n            <td>Default file compression zstd level. For higher compression rates, it can be configured to 9, but the read and write speed will significantly decrease.</td>\n        </tr>\n        <tr>\n            <td><h5>file.format</h5></td>\n            <td style="word-wrap: break-word;">"parquet"</td>\n            <td>String</td>\n            <td>Specify the message format of data files, currently orc, parquet and avro are supported.</td>\n        </tr>\n        <tr>\n            <td><h5>file.format.per.level</h5></td>\n            <td style="word-wrap: break-word;"></td>\n            <td>Map</td>\n            <td>Define different file format for different level, you can add the conf like this: \'file.format.per.level\' = \'0:avro,3:parquet\', if the file format for level is not provided, the default format which set by `file.format` will be used.</td>\n        </tr>\n        <tr>\n            <td><h5>file.suffix.include.compression</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether to add file compression type in the file name of data file and changelog file.</td>\n        </tr>\n        <tr>\n            <td><h5>force-lookup</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether to force the use of lookup for compaction.</td>\n        </tr>\n        <tr>\n            <td><h5>format-table.commit-hive-sync-url</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>Format table commit hive sync uri.</td>\n        </tr>\n        <tr>\n            <td><h5>format-table.file.compression</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>Format table file compression.</td>\n        </tr>\n        <tr>\n            <td><h5>format-table.implementation</h5></td>\n            <td style="word-wrap: break-word;">paimon</td>\n            <td><p>Enum</p></td>\n            <td>Format table uses paimon or engine.<br /><br />Possible values:<ul><li>"paimon": Paimon format table implementation.</li><li>"engine": Engine format table implementation.</li></ul></td>\n        </tr>\n        <tr>\n            <td><h5>format-table.partition-path-only-value</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Format table file path only contain partition value.</td>\n        </tr>\n        <tr>\n            <td><h5>full-compaction.delta-commits</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Integer</td>\n            <td>For streaming write, full compaction will be constantly triggered after delta commits. For batch write, full compaction will be triggered with each commit as long as this value is greater than 0.</td>\n        </tr>\n        <tr>\n            <td><h5>global-index.build.max-parallelism</h5></td>\n            <td style="word-wrap: break-word;">4096</td>\n            <td>Integer</td>\n            <td>The max parallelism of Flink/Spark for building global index.</td>\n        </tr>\n        <tr>\n            <td><h5>global-index.build.max-shard</h5></td>\n            <td style="word-wrap: break-word;">32</td>\n            <td>Integer</td>\n            <td>The preferred max number of shards for building global index. If the number of shards calculated by \'global-index.row-count-per-shard\' exceeds this value, max-shard will be automatically increased to accommodate the data volume while keeping \'global-index.row-count-per-shard\' unchanged.</td>\n        </tr>\n        <tr>\n            <td><h5>global-index.column-update-action</h5></td>\n            <td style="word-wrap: break-word;">THROW_ERROR</td>\n            <td><p>Enum</p></td>\n            <td>Defines the action to take when an update modifies columns that are covered by a global index. IGNORE leaves existing index files unchanged and may make the index stale.<br /><br />Possible values:<ul><li>"THROW_ERROR"</li><li>"DROP_PARTITION_INDEX"</li><li>"IGNORE"</li></ul></td>\n        </tr>\n        <tr>\n            <td><h5>global-index.enabled</h5></td>\n            <td style="word-wrap: break-word;">true</td>\n            <td>Boolean</td>\n            <td>Whether to enable global index for scan.</td>\n        </tr>\n        <tr>\n            <td><h5>global-index.external-path</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>Global index root directory, if not set, the global index files will be stored under the &lt;table-root-directory&gt;/index.</td>\n        </tr>\n        <tr>\n            <td><h5>global-index.row-count-per-shard</h5></td>\n            <td style="word-wrap: break-word;">100000</td>\n            <td>Long</td>\n            <td>Row count per shard for global index.</td>\n        </tr>\n        <tr>\n            <td><h5>global-index.search-mode</h5></td>\n            <td style="word-wrap: break-word;">fast</td>\n            <td><p>Enum</p></td>\n            <td>Search mode for global index queries. Supported values are \'fast\', \'full\', and \'detail\'.<br /><br />Possible values:<ul><li>"fast": Only search indexed data.</li><li>"full": Use snapshot next row id and global index coverage to detect missing row ids, and scan raw data only when a gap exists.</li><li>"detail": Scan data files to find exact unindexed rows. This can handle index invalidation caused by updates or rewrites.</li></ul></td>\n        </tr>\n        <tr>\n            <td><h5>global-index.thread-num</h5></td>\n            <td style="word-wrap: break-word;">32</td>\n            <td>Integer</td>\n            <td>The maximum number of concurrent threads for global index I/O.</td>\n        </tr>\n        <tr>\n            <td><h5>ignore-delete</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether to ignore delete records.</td>\n        </tr>\n        <tr>\n            <td><h5>ignore-update-before</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether to ignore update-before records.</td>\n        </tr>\n        <tr>\n            <td><h5>incremental-between</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>Read incremental changes between start snapshot (exclusive) and end snapshot (inclusive), for example, \'5,10\' means changes between snapshot 5 and snapshot 10.</td>\n        </tr>\n        <tr>\n            <td><h5>incremental-between-scan-mode</h5></td>\n            <td style="word-wrap: break-word;">auto</td>\n            <td><p>Enum</p></td>\n            <td>Scan kind when Read incremental changes between start snapshot (exclusive) and end snapshot (inclusive). <br /><br />Possible values:<ul><li>"auto": Scan changelog files for the table which produces changelog files. Otherwise, scan newly changed files.</li><li>"delta": Scan newly changed files between snapshots.</li><li>"changelog": Scan changelog files between snapshots.</li><li>"diff": Get diff by comparing data of end snapshot with data of start snapshot.</li></ul></td>\n        </tr>\n        <tr>\n            <td><h5>incremental-between-tag-to-snapshot</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether to read incremental changes between the snapshot corresponding to the tag.</td>\n        </tr>\n        <tr>\n            <td><h5>incremental-between-timestamp</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>Read incremental changes between start timestamp (exclusive) and end timestamp (inclusive), for example, \'t1,t2\' means changes between timestamp t1 and timestamp t2.</td>\n        </tr>\n        <tr>\n            <td><h5>incremental-to-auto-tag</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>Used to specify the end tag (inclusive), and Paimon will find an earlier tag and return changes between them. If the tag doesn\'t exist or the earlier tag doesn\'t exist, return empty. This option requires \'tag.creation-period\' and \'tag.period-formatter\' configured.</td>\n        </tr>\n        <tr>\n            <td><h5>index-file-in-data-file-dir</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether index file in data file directory.</td>\n        </tr>\n        <tr>\n            <td><h5>local-merge-buffer-size</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>MemorySize</td>\n            <td>Local merge will buffer and merge input records before they\'re shuffled by bucket and written into sink. The buffer will be flushed when it is full.\nMainly to resolve data skew on primary keys. We recommend starting with 64 mb when trying out this feature.</td>\n        </tr>\n        <tr>\n            <td><h5>local-sort.max-num-file-handles</h5></td>\n            <td style="word-wrap: break-word;">128</td>\n            <td>Integer</td>\n            <td>The maximal fan-in for external merge sort. It limits the number of file handles. If it is too small, may cause intermediate merging. But if it is too large, it will cause too many files opened at the same time, consume memory and lead to random reading.</td>\n        </tr>\n        <tr>\n            <td><h5>lookup-compact</h5></td>\n            <td style="word-wrap: break-word;">RADICAL</td>\n            <td><p>Enum</p></td>\n            <td>Lookup compact mode used for lookup compaction.<br /><br />Possible values:<ul><li>"RADICAL"</li><li>"GENTLE"</li></ul></td>\n        </tr>\n        <tr>\n            <td><h5>lookup-compact.max-interval</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Integer</td>\n            <td>The max interval for a gentle mode lookup compaction to be triggered. For every interval, a forced lookup compaction will be performed to flush L0 files to higher level. This option is only valid when lookup-compact mode is gentle.</td>\n        </tr>\n        <tr>\n            <td><h5>lookup-wait</h5></td>\n            <td style="word-wrap: break-word;">true</td>\n            <td>Boolean</td>\n            <td>When need to lookup, commit will wait for compaction by lookup.</td>\n        </tr>\n        <tr>\n            <td><h5>lookup.blob-as-descriptor</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>When enabled, the lookup join stores only the BlobDescriptor (a lightweight reference containing file URI, offset, and length) for BLOB fields instead of the full blob bytes. This dramatically reduces local disk and memory usage for tables with large BLOB columns (e.g., images, videos). The downstream consumer receives the serialized BlobDescriptor bytes and can resolve the actual blob content on demand.</td>\n        </tr>\n        <tr>\n            <td><h5>lookup.cache-file-retention</h5></td>\n            <td style="word-wrap: break-word;">1 h</td>\n            <td>Duration</td>\n            <td>The cached files retention time for lookup. After the file expires, if there is a need for access, it will be re-read from the DFS to build an index on the local disk.</td>\n        </tr>\n        <tr>\n            <td><h5>lookup.cache-max-disk-size</h5></td>\n            <td style="word-wrap: break-word;">infinite</td>\n            <td>MemorySize</td>\n            <td>Max disk size for lookup cache, you can use this option to limit the use of local disks.</td>\n        </tr>\n        <tr>\n            <td><h5>lookup.cache-max-memory-size</h5></td>\n            <td style="word-wrap: break-word;">256 mb</td>\n            <td>MemorySize</td>\n            <td>Max memory size for lookup cache.</td>\n        </tr>\n        <tr>\n            <td><h5>lookup.cache-spill-compression</h5></td>\n            <td style="word-wrap: break-word;">"zstd"</td>\n            <td>String</td>\n            <td>Spill compression for lookup cache, currently zstd, none, lz4 and lzo are supported.</td>\n        </tr>\n        <tr>\n            <td><h5>lookup.cache.bloom.filter.enabled</h5></td>\n            <td style="word-wrap: break-word;">true</td>\n            <td>Boolean</td>\n            <td>Whether to enable the bloom filter for lookup cache.</td>\n        </tr>\n        <tr>\n            <td><h5>lookup.cache.bloom.filter.fpp</h5></td>\n            <td style="word-wrap: break-word;">0.05</td>\n            <td>Double</td>\n            <td>Define the default false positive probability for lookup cache bloom filters.</td>\n        </tr>\n        <tr>\n            <td><h5>lookup.cache.high-priority-pool-ratio</h5></td>\n            <td style="word-wrap: break-word;">0.25</td>\n            <td>Double</td>\n            <td>The fraction of cache memory that is reserved for high-priority data like index, filter.</td>\n        </tr>\n        <tr>\n            <td><h5>lookup.hash-load-factor</h5></td>\n            <td style="word-wrap: break-word;">0.75</td>\n            <td>Float</td>\n            <td>The index load factor for lookup.</td>\n        </tr>\n        <tr>\n            <td><h5>lookup.merge-buffer-size</h5></td>\n            <td style="word-wrap: break-word;">8 mb</td>\n            <td>MemorySize</td>\n            <td>Buffer memory size for one key merging in lookup.</td>\n        </tr>\n        <tr>\n            <td><h5>lookup.merge-records-threshold</h5></td>\n            <td style="word-wrap: break-word;">1024</td>\n            <td>Integer</td>\n            <td>Threshold for merging records to binary buffer in lookup.</td>\n        </tr>\n        <tr>\n            <td><h5>lookup.remote-file.enabled</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether to enable the remote file for lookup.</td>\n        </tr>\n        <tr>\n            <td><h5>lookup.remote-file.level-threshold</h5></td>\n            <td style="word-wrap: break-word;">-2147483648</td>\n            <td>Integer</td>\n            <td>Level threshold of lookup to generate remote lookup files. Level files below this threshold will not generate remote lookup files.</td>\n        </tr>\n        <tr>\n            <td><h5>manifest-sort.enabled</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether to invoke manifest sort rewrite during commit.<br />Note: enabling this changes the semantics of \'manifest.merge-min-count\'. In the sort rewrite path, small manifest files within the rewrite budget are sorted and merged directly, so the minimum-count gate no longer prevents merging a small number of under-budget manifest files when full compaction is not triggered.</td>\n        </tr>\n        <tr>\n            <td><h5>manifest-sort.max-rewrite-size</h5></td>\n            <td style="word-wrap: break-word;">256 mb</td>\n            <td>MemorySize</td>\n            <td>Maximum total size of manifest files to rewrite in a single sort rewrite pass. Sections exceeding this limit are skipped. Set to a larger value to allow more aggressive sort rewriting. The cap only limits the sorted rewrite portion and full/minor cleanup may still happen beyond it.</td>\n        </tr>\n        <tr>\n            <td><h5>manifest-sort.partition-field</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>Partition field name to sort manifest entries by. Validated by schema validation, if not configured, defaults to the first partition field.</td>\n        </tr>\n        <tr>\n            <td><h5>manifest.compression</h5></td>\n            <td style="word-wrap: break-word;">"zstd"</td>\n            <td>String</td>\n            <td>Default file compression for manifest.</td>\n        </tr>\n        <tr>\n            <td><h5>manifest.delete-file-drop-stats</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>For DELETE manifest entry in manifest file, drop stats to reduce memory and storage. Default value is false only for compatibility of old reader.</td>\n        </tr>\n        <tr>\n            <td><h5>manifest.format</h5></td>\n            <td style="word-wrap: break-word;">"avro"</td>\n            <td>String</td>\n            <td>Specify the message format of manifest files.</td>\n        </tr>\n        <tr>\n            <td><h5>manifest.full-compaction-threshold-size</h5></td>\n            <td style="word-wrap: break-word;">16 mb</td>\n            <td>MemorySize</td>\n            <td>The size threshold for triggering full compaction of manifest.</td>\n        </tr>\n        <tr>\n            <td><h5>manifest.merge-min-count</h5></td>\n            <td style="word-wrap: break-word;">30</td>\n            <td>Integer</td>\n            <td>To avoid frequent manifest merges, this parameter specifies the minimum number of ManifestFileMeta to merge.<br />Note: when \'manifest-sort.enabled\' is true, this minimum-count gate is only applied to the trailing sub-segment of a section that exceeds \'manifest-sort.max-rewrite-size\'. Small under-budget sections are sorted and rewritten directly, so two small manifest files may be merged into one even when their count is below this threshold and full compaction is not triggered.</td>\n        </tr>\n        <tr>\n            <td><h5>manifest.target-file-size</h5></td>\n            <td style="word-wrap: break-word;">8 mb</td>\n            <td>MemorySize</td>\n            <td>Suggested file size of a manifest file.</td>\n        </tr>\n        <tr>\n            <td><h5>merge-engine</h5></td>\n            <td style="word-wrap: break-word;">deduplicate</td>\n            <td><p>Enum</p></td>\n            <td>Specify the merge engine for table with primary key.<br /><br />Possible values:<ul><li>"deduplicate": De-duplicate and keep the last row.</li><li>"partial-update": Partial update non-null fields.</li><li>"aggregation": Aggregate fields with same primary key.</li><li>"first-row": De-duplicate and keep the first row.</li></ul></td>\n        </tr>\n        <tr>\n            <td><h5>metadata.stats-dense-store</h5></td>\n            <td style="word-wrap: break-word;">true</td>\n            <td>Boolean</td>\n            <td>Whether to store statistic densely in metadata (manifest files), which will significantly reduce the storage size of metadata when the none statistic mode is set.<br />Note, when this mode is enabled with \'metadata.stats-mode:none\', the Paimon sdk in reading engine requires at least version 0.9.1 or 1.0.0 or higher.</td>\n        </tr>\n        <tr>\n            <td><h5>metadata.stats-keep-first-n-columns</h5></td>\n            <td style="word-wrap: break-word;">-1</td>\n            <td>Integer</td>\n            <td>Define how many columns\' stats are kept in metadata file from front to end. Default value \'-1\' means ignoring this config.</td>\n        </tr>\n        <tr>\n            <td><h5>metadata.stats-mode</h5></td>\n            <td style="word-wrap: break-word;">"truncate(16)"</td>\n            <td>String</td>\n            <td>The mode of metadata stats collection. none, counts, truncate(16), full is available.<br /><ul><li>"none": means disable the metadata stats collection.</li></ul><ul><li>"counts" means only collect the null count.</li></ul><ul><li>"full": means collect the null count, min/max value.</li></ul><ul><li>"truncate(16)": means collect the null count, min/max value with truncated length of 16.</li></ul><ul><li>Field level stats mode can be specified by fields.{field_name}.stats-mode</li></ul></td>\n        </tr>\n        <tr>\n            <td><h5>metadata.stats-mode.per.level</h5></td>\n            <td style="word-wrap: break-word;"></td>\n            <td>Map</td>\n            <td>Define different \'metadata.stats-mode\' for different level, you can add the conf like this: \'metadata.stats-mode.per.level\' = \'0:none\', if the metadata.stats-mode for level is not provided, the default mode which set by `metadata.stats-mode` will be used.</td>\n        </tr>\n        <tr>\n            <td><h5>metastore.partitioned-table</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether to create this table as a partitioned table in metastore.\nFor example, if you want to list all partitions of a Paimon table in Hive, you need to create this table as a partitioned table in Hive metastore.\nThis config option does not affect the default filesystem metastore.\nFor an internal format table in a REST catalog, it also makes the catalog own the table\'s partitions: a scan reads the partitions registered there and a write registers the ones it wrote, instead of listing the table directory.</td>\n        </tr>\n        <tr>\n            <td><h5>metastore.tag-to-partition</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>Whether to create this table as a partitioned table for mapping non-partitioned table tags in metastore. This allows the Hive engine to view this table in a partitioned table view and use partitioning field to read specific partitions (specific tags).</td>\n        </tr>\n        <tr>\n            <td><h5>metastore.tag-to-partition.preview</h5></td>\n            <td style="word-wrap: break-word;">none</td>\n            <td><p>Enum</p></td>\n            <td>Whether to preview tag of generated snapshots in metastore. This allows the Hive engine to query specific tag before creation.<br /><br />Possible values:<ul><li>"none": No automatically created tags.</li><li>"process-time": Based on the time of the machine, create TAG once the processing time passes period time plus delay.</li><li>"watermark": Based on the watermark of the input, create TAG once the watermark passes period time plus delay.</li><li>"batch": In the batch processing scenario, the tag corresponding to the current snapshot is generated after the task is completed.</li></ul></td>\n        </tr>\n        <tr>\n            <td><h5>num-levels</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Integer</td>\n            <td>Total level number, for example, there are 3 levels, including 0,1,2 levels.</td>\n        </tr>\n        <tr>\n            <td><h5>num-sorted-run.compaction-trigger</h5></td>\n            <td style="word-wrap: break-word;">5</td>\n            <td>Integer</td>\n            <td>The sorted run number to trigger compaction. Includes level0 files (one file one sorted run) and high-level runs (one level one sorted run).</td>\n        </tr>\n        <tr>\n            <td><h5>num-sorted-run.stop-trigger</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Integer</td>\n            <td>The number of sorted runs that trigger the stopping of writes, the default value is \'num-sorted-run.compaction-trigger\' + 3.</td>\n        </tr>\n        <tr>\n            <td><h5>overwrite-upgrade</h5></td>\n            <td style="word-wrap: break-word;">true</td>\n            <td>Boolean</td>\n            <td>Whether to try upgrading the data files after overwriting a primary key table.</td>\n        </tr>\n        <tr>\n            <td><h5>page-size</h5></td>\n            <td style="word-wrap: break-word;">64 kb</td>\n            <td>MemorySize</td>\n            <td>Memory page size.</td>\n        </tr>\n        <tr>\n            <td><h5>parquet.enable.dictionary</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Integer</td>\n            <td>Turn off the dictionary encoding for all fields in parquet.</td>\n        </tr>\n        <tr>\n            <td><h5>partial-update.remove-record-on-delete</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether to remove the whole row in partial-update engine when -D records are received.</td>\n        </tr>\n        <tr>\n            <td><h5>partial-update.remove-record-on-sequence-group</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>When -D records of the given sequence groups are received, remove the whole row.</td>\n        </tr>\n        <tr>\n            <td><h5>partition</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>Define partition by table options, cannot define partition on DDL and table options at the same time.</td>\n        </tr>\n        <tr>\n            <td><h5>partition.default-name</h5></td>\n            <td style="word-wrap: break-word;">"__DEFAULT_PARTITION__"</td>\n            <td>String</td>\n            <td>The default partition name in case the dynamic partition column value is null/empty string.</td>\n        </tr>\n        <tr>\n            <td><h5>partition.end-input-to-done</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether mark the done status to indicate that the data is ready when end input.</td>\n        </tr>\n        <tr>\n            <td><h5>partition.expiration-batch-size</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Integer</td>\n            <td>The batch size of partition expiration. By default, all partitions to be expired will be expired together, which may cause a risk of out-of-memory. Use this parameter to divide partition expiration process and mitigate memory pressure.</td>\n        </tr>\n        <tr>\n            <td><h5>partition.expiration-check-interval</h5></td>\n            <td style="word-wrap: break-word;">1 h</td>\n            <td>Duration</td>\n            <td>The check interval of partition expiration.</td>\n        </tr>\n        <tr>\n            <td><h5>partition.expiration-max-num</h5></td>\n            <td style="word-wrap: break-word;">100</td>\n            <td>Integer</td>\n            <td>The default deleted num of partition expiration.</td>\n        </tr>\n        <tr>\n            <td><h5>partition.expiration-strategy</h5></td>\n            <td style="word-wrap: break-word;">"values-time"</td>\n            <td>String</td>\n            <td>The strategy determines how to extract the partition time and compare it with the current time.<ul><li>"values-time": This strategy compares the time extracted from the partition value with the current time.</li><li>"update-time": This strategy compares the last update time of the partition with the current time.</li></ul></td>\n        </tr>\n        <tr>\n            <td><h5>partition.expiration-time</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Duration</td>\n            <td>The expiration interval of a partition. A partition will be expired if it\'s lifetime is over this value. Partition time is extracted from the partition value.</td>\n        </tr>\n        <tr>\n            <td><h5>partition.idle-time-to-report-statistic</h5></td>\n            <td style="word-wrap: break-word;">0 ms</td>\n            <td>Duration</td>\n            <td>Set a time duration when a partition has no new data after this time duration, start to report the partition statistics to hms.</td>\n        </tr>\n        <tr>\n            <td><h5>partition.legacy-name</h5></td>\n            <td style="word-wrap: break-word;">true</td>\n            <td>Boolean</td>\n            <td>The legacy partition name is using `toString` for all types. If false, using cast to string for all types.</td>\n        </tr>\n        <tr>\n            <td><h5>partition.mark-done-action</h5></td>\n            <td style="word-wrap: break-word;">"success-file"</td>\n            <td>String</td>\n            <td>Action to mark a partition done is to notify the downstream application that the partition has finished writing, the partition is ready to be read.<br />1. \'success-file\': add \'_success\' file to directory.<br />2. \'done-partition\': add \'xxx.done\' partition to metastore.<br />3. \'mark-event\': mark partition event to metastore.<br />4. \'http-report\': report partition mark done to remote http server.<br />5. \'custom\': use policy class to create a mark-partition policy.<br />Both can be configured at the same time: \'done-partition,success-file,mark-event,custom\'.</td>\n        </tr>\n        <tr>\n            <td><h5>partition.mark-done-action.custom.class</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>The partition mark done class for implement PartitionMarkDoneAction interface. Only work in custom mark-done-action.</td>\n        </tr>\n        <tr>\n            <td><h5>partition.mark-done-action.http.params</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>Http client request parameters will be written to the request body, this can only be used by http-report partition mark done action.</td>\n        </tr>\n        <tr>\n            <td><h5>partition.mark-done-action.http.url</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>Mark done action will reports the partition to the remote http server, this can only be used by http-report partition mark done action.</td>\n        </tr>\n        <tr>\n            <td><h5>partition.sink-strategy</h5></td>\n            <td style="word-wrap: break-word;">NONE</td>\n            <td><p>Enum</p></td>\n            <td>This is only for partitioned append table or postpone pk table, and the purpose is to reduce small files and improve write performance. Through this repartitioning strategy to reduce the number of partitions written by each task to as few as possible.<ul><li>none: Rebalanced or Forward partitioning, this is the default behavior, this strategy is suitable for the number of partitions you write in a batch is much smaller than write parallelism.</li><li>hash: Hash the partitions value, this strategy is suitable for the number of partitions you write in a batch is greater equals than write parallelism.</li><li>partition_dynamic: Dynamically adjusts shuffle strategy based on partition key traffic patterns. This mode monitors data distribution across partitions and rebalances load across downstream subtasks. Suitable when partition traffic is skewed and you want balanced write throughput.</li></ul><br /><br />Possible values:<ul><li>"NONE"</li><li>"HASH"</li><li>"PARTITION_DYNAMIC"</li></ul></td>\n        </tr>\n        <tr>\n            <td><h5>partition.timestamp-format.strict</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>When enabled, if a partition value does not match the \'partition.timestamp-formatter\' or \'partition.timestamp-pattern\' configuration, an error will be thrown during writing. This helps prevent dirty partition directories caused by incorrectly specified partition fields.</td>\n        </tr>\n        <tr>\n            <td><h5>partition.timestamp-formatter</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>The formatter to format timestamp from string. It can be used with \'partition.timestamp-pattern\' to create a formatter using the specified value.<ul><li>Default formatter is \'yyyy-MM-dd HH:mm:ss\' and \'yyyy-MM-dd\'.</li><li>Supports multiple partition fields like \'$year-$month-$day $hour:00:00\'.</li><li>The timestamp-formatter is compatible with Java\'s DateTimeFormatter.</li></ul></td>\n        </tr>\n        <tr>\n            <td><h5>partition.timestamp-pattern</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>You can specify a pattern to get a timestamp from partitions. The formatter pattern is defined by \'partition.timestamp-formatter\'.<ul><li>By default, read from the first field.</li><li>If the timestamp in the partition is a single field called \'dt\', you can use \'$dt\'.</li><li>If it is spread across multiple fields for year, month, day, and hour, you can use \'$year-$month-$day $hour:00:00\'.</li><li>If the timestamp is in fields dt and hour, you can use \'$dt $hour:00:00\'.</li></ul></td>\n        </tr>\n        <tr>\n            <td><h5>pk-bitmap.index.columns</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>Comma-separated columns indexed by primary-key Bitmap indexes.</td>\n        </tr>\n        <tr>\n            <td><h5>pk-btree.index.columns</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>Comma-separated columns indexed by primary-key BTree indexes.</td>\n        </tr>\n        <tr>\n            <td><h5>pk-clustering-override</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Enables clustering by non-primary key fields. When set to true, the physical sort order of data files is determined by the configured \'clustering.columns\' instead of the primary key, optimizing query performance for non-PK columns.</td>\n        </tr>\n        <tr>\n            <td><h5>pk-full-text.index.columns</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>Comma-separated character columns indexed by primary-key full-text indexes. The first release supports exactly one column.</td>\n        </tr>\n        <tr>\n            <td><h5>pk-vector.index.columns</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>Comma-separated VECTOR columns indexed by primary-key vector indexes. Each column owns one index and must define fields.&lt;column&gt;.pk-vector.index.type. Index options and distance metric are also field-scoped. The first release supports exactly one column.</td>\n        </tr>\n        <tr>\n            <td><h5>postpone.batch-write-fixed-bucket</h5></td>\n            <td style="word-wrap: break-word;">true</td>\n            <td>Boolean</td>\n            <td>Whether to write the data into fixed bucket for batch writing a postpone bucket table.</td>\n        </tr>\n        <tr>\n            <td><h5>postpone.batch-write-fixed-bucket.max-parallelism</h5></td>\n            <td style="word-wrap: break-word;">2048</td>\n            <td>Integer</td>\n            <td>The number of partitions for global index.</td>\n        </tr>\n        <tr>\n            <td><h5>postpone.default-bucket-num</h5></td>\n            <td style="word-wrap: break-word;">1</td>\n            <td>Integer</td>\n            <td>Bucket number for the partitions compacted for the first time in postpone bucket tables.</td>\n        </tr>\n        <tr>\n            <td><h5>postpone.target-row-num-per-bucket</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Long</td>\n            <td>Target row number per bucket for partitions compacted from postpone bucket files for the first time.</td>\n        </tr>\n        <tr>\n            <td><h5>primary-key</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>Define primary key by table options, cannot define primary key on DDL and table options at the same time.</td>\n        </tr>\n        <tr>\n            <td><h5>query-auth.enabled</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Enable query auth to give Catalog the opportunity to perform column level and row level permission validation on queries.</td>\n        </tr>\n        <tr>\n            <td><h5>read.batch-size</h5></td>\n            <td style="word-wrap: break-word;">1024</td>\n            <td>Integer</td>\n            <td>Read batch size for any file format if it supports.</td>\n        </tr>\n        <tr>\n            <td><h5>record-level.expire-time</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Duration</td>\n            <td>Record level expire time for primary key table, expiration happens in compaction, there is no strong guarantee to expire records in time. You must specific \'record-level.time-field\' too.</td>\n        </tr>\n        <tr>\n            <td><h5>record-level.time-field</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>Time field for record level expire. It supports the following types: `timestamps in seconds with INT`,`timestamps in seconds with BIGINT`, `timestamps in milliseconds with BIGINT` or `timestamp`.</td>\n        </tr>\n        <tr>\n            <td><h5>row-tracking.enabled</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether enable unique row id for append table.</td>\n        </tr>\n        <tr>\n            <td><h5>row-tracking.partition-group-on-commit</h5></td>\n            <td style="word-wrap: break-word;">true</td>\n            <td>Boolean</td>\n            <td>When row-tracking is enabled, whether to group new file metas by partition before commit, so that assigned row IDs are contiguous within each partition.This is useful if you want to build global indices on this table. </td>\n        </tr>\n        <tr>\n            <td><h5>rowkind.field</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>The field that generates the row kind for primary key table, the row kind determines which data is \'+I\', \'-U\', \'+U\' or \'-D\'.</td>\n        </tr>\n        <tr>\n            <td><h5>scan.bounded.watermark</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Long</td>\n            <td>End condition "watermark" for bounded streaming mode. Stream reading will end when a larger watermark snapshot is encountered.</td>\n        </tr>\n        <tr>\n            <td><h5>scan.bucket</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Integer</td>\n            <td>Specify a single bucket to scan. This option filters manifest entries and only plans splits for the given bucket. It is only supported for fixed-bucket primary key tables (bucket &gt; 0). It cannot be used with postpone bucket tables.</td>\n        </tr>\n        <tr>\n            <td><h5>scan.creation-time-millis</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Long</td>\n            <td>Optional timestamp used in case of "from-creation-timestamp" scan mode.</td>\n        </tr>\n        <tr>\n            <td><h5>scan.fallback-branch</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>When a batch job queries from a table, if a partition does not exist in the current branch, the reader will try to get this partition from this fallback branch.</td>\n        </tr>\n        <tr>\n            <td><h5>scan.fallback-branch.read-fail-fast</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether to fail the read immediately when reading from a fallback branch throws. By default the failure is logged with the full stack trace and the reader falls through to the current branch, which can mask data issues. Set this to true to surface fallback branch errors to the caller instead.</td>\n        </tr>\n        <tr>\n            <td><h5>scan.fallback-delta-branch</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>When a batch job queries from a chain table, if a partition does not exist in either main or snapshot branch, the reader will try to get this partition from chain snapshot and delta branch together.</td>\n        </tr>\n        <tr>\n            <td><h5>scan.fallback-snapshot-branch</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>When a batch job queries from a chain table, if a partition does not exist in the main branch, the reader will try to get this partition from chain snapshot branch.</td>\n        </tr>\n        <tr>\n            <td><h5>scan.file-creation-time-millis</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Long</td>\n            <td>After configuring this time, only the data files created after this time will be read. It is independent of snapshots, but it is imprecise filtering (depending on whether or not compaction occurs).</td>\n        </tr>\n        <tr>\n            <td><h5>scan.ignore-corrupt-files</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Ignore corrupt files while scanning.</td>\n        </tr>\n        <tr>\n            <td><h5>scan.ignore-lost-files</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Ignore lost files while scanning.</td>\n        </tr>\n        <tr>\n            <td><h5>scan.manifest.parallelism</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Integer</td>\n            <td>The parallelism of scanning manifest files, default value is the size of cpu processor. Note: Scale-up this parameter will increase memory usage while scanning manifest files. We can consider downsize it when we encounter an out of memory exception while scanning</td>\n        </tr>\n        <tr>\n            <td><h5>scan.max-splits-per-task</h5></td>\n            <td style="word-wrap: break-word;">10</td>\n            <td>Integer</td>\n            <td>Max split size should be cached for one task while scanning. If splits size cached in enumerator are greater than tasks size multiply by this value, scanner will pause scanning.</td>\n        </tr>\n        <tr>\n            <td><h5>scan.mode</h5></td>\n            <td style="word-wrap: break-word;">default</td>\n            <td><p>Enum</p></td>\n            <td>Specify the scanning behavior of the source.<br /><br />Possible values:<ul><li>"default": Determines actual startup mode according to other table properties. If "scan.timestamp-millis" is set the actual startup mode will be "from-timestamp", and if "scan.snapshot-id" or "scan.tag-name" is set the actual startup mode will be "from-snapshot". Otherwise the actual startup mode will be "latest-full".</li><li>"latest-full": For streaming sources, produces the latest snapshot on the table upon first startup, and continue to read the latest changes. For batch sources, just produce the latest snapshot but does not read new changes.</li><li>"full": Deprecated. Same as "latest-full".</li><li>"latest": For streaming sources, continuously reads latest changes without producing a snapshot at the beginning. For batch sources, behaves the same as the "latest-full" startup mode.</li><li>"compacted-full": For streaming sources, produces a snapshot after the latest compaction on the table upon first startup, and continue to read the latest changes. For batch sources, just produce a snapshot after the latest compaction but does not read new changes. Snapshots of full compaction are picked when scheduled full-compaction is enabled.</li><li>"from-timestamp": For streaming sources, continuously reads changes starting from timestamp specified by "scan.timestamp-millis", without producing a snapshot at the beginning. For batch sources, produces a snapshot at timestamp specified by "scan.timestamp-millis" but does not read new changes.</li><li>"from-creation-timestamp": For streaming sources and batch sources, If timestamp specified by "scan.creation-time-millis" is during in the range of earliest snapshot and latest snapshot: mode is from-snapshot which snapshot is equal or later the timestamp. If timestamp is earlier than earliest snapshot or later than latest snapshot, mode is from-file-creation-time.</li><li>"from-file-creation-time": For streaming and batch sources, consumes a snapshot and filters the data files by creation time. For streaming sources, upon first startup, and continue to read the latest changes.</li><li>"from-snapshot": For streaming sources, continuously reads changes starting from snapshot specified by "scan.snapshot-id", without producing a snapshot at the beginning. For batch sources, produces a snapshot specified by "scan.snapshot-id" or "scan.tag-name" but does not read new changes.</li><li>"from-snapshot-full": For streaming sources, produces from snapshot specified by "scan.snapshot-id" on the table upon first startup, and continuously reads changes. For batch sources, produces a snapshot specified by "scan.snapshot-id" but does not read new changes.</li><li>"incremental": Read incremental changes between start and end snapshot or timestamp.</li></ul></td>\n        </tr>\n        <tr>\n            <td><h5>scan.plan-auto-tag-for-read.time-retained</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Duration</td>\n            <td>When set, a temporary tag will be auto-created during batch scan planning to protect the read snapshot from expiration. The value specifies the tag\'s TTL. Should be longer than the longest expected batch read duration.</td>\n        </tr>\n        <tr>\n            <td><h5>scan.plan-sort-partition</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether to sort plan files by partition fields, this allows you to read according to the partition order, even if your partition writes are out of order.<br />It is recommended that you use this for streaming read of the \'append-only\' table. By default, streaming read will read the full snapshot first. In order to avoid the disorder reading for partitions, you can open this option.</td>\n        </tr>\n        <tr>\n            <td><h5>scan.primary-branch</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>When a batch job queries from a table, if a partition exists in the primary branch, the reader will read this partition from the primary branch. Otherwise, the reader will read this partition from the current branch.</td>\n        </tr>\n        <tr>\n            <td><h5>scan.snapshot-id</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Long</td>\n            <td>Optional snapshot id used in case of "from-snapshot" or "from-snapshot-full" scan mode</td>\n        </tr>\n        <tr>\n            <td><h5>scan.tag-name</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>Optional tag name used in case of "from-snapshot" scan mode.</td>\n        </tr>\n        <tr>\n            <td><h5>scan.timestamp</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>Optional timestamp used in case of "from-timestamp" scan mode, it will be automatically converted to timestamp in unix milliseconds, use local time zone</td>\n        </tr>\n        <tr>\n            <td><h5>scan.timestamp-millis</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Long</td>\n            <td>Optional timestamp used in case of "from-timestamp" scan mode. If there is no snapshot earlier than this time, the earliest snapshot will be chosen.</td>\n        </tr>\n        <tr>\n            <td><h5>scan.watermark</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Long</td>\n            <td>Optional watermark used in case of "from-snapshot" scan mode. If there is no snapshot later than this watermark, will throw an exceptions.</td>\n        </tr>\n        <tr>\n            <td><h5>sequence.field</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>The field that generates the sequence number for primary key table, the sequence number determines which data is the most recent.</td>\n        </tr>\n        <tr>\n            <td><h5>sequence.field.sort-order</h5></td>\n            <td style="word-wrap: break-word;">ascending</td>\n            <td><p>Enum</p></td>\n            <td>Specify the order of sequence.field.<br /><br />Possible values:<ul><li>"ascending": specifies sequence.field sort order is ascending.</li><li>"descending": specifies sequence.field sort order is descending.</li></ul></td>\n        </tr>\n        <tr>\n            <td><h5>sequence.snapshot-ordering</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>When enabled, merge uses the commit snapshot id as the ordering key for primary-key conflicts: records from later snapshots always win. Designed for multi-writer scenarios on the same primary-key table where wall-clock sequence numbers cannot be globally ordered. The order of records within the same snapshot is not guaranteed. Mutually exclusive with sequence.field. Requires a primary-key table with write-only=true. Inline compaction is not allowed because snapshot ids are assigned only after commit. To compact such tables, run a dedicated compaction job/action with write-only=false.</td>\n        </tr>\n        <tr>\n            <td><h5>sink.process-time-zone</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>The time zone to parse the long process time to TIMESTAMP value. The default value is JVM\'s default time zone. If you want to specify a time zone, you should either set a full name such as \'America/Los_Angeles\' or a custom zone id such as \'GMT-08:00\'. This option currently is used for extract tag name.</td>\n        </tr>\n        <tr>\n            <td><h5>sink.watermark-time-zone</h5></td>\n            <td style="word-wrap: break-word;">"UTC"</td>\n            <td>String</td>\n            <td>The time zone to parse the long watermark value to TIMESTAMP value. The default value is \'UTC\', which means the watermark is defined on TIMESTAMP column or not defined. If the watermark is defined on TIMESTAMP_LTZ column, the time zone of watermark is user configured time zone, the value should be the user configured local time zone. The option value is either a full name such as \'America/Los_Angeles\', or a custom timezone id such as \'GMT-08:00\'.</td>\n        </tr>\n        <tr>\n            <td><h5>snapshot.clean-empty-directories</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether to try to clean empty directories when expiring snapshots, if enabled, please note:<ul><li>hdfs: may print exceptions in NameNode.</li><li>oss/s3: may cause performance issue.</li></ul></td>\n        </tr>\n        <tr>\n            <td><h5>snapshot.expire.execution-mode</h5></td>\n            <td style="word-wrap: break-word;">sync</td>\n            <td><p>Enum</p></td>\n            <td>Specifies the execution mode of expire.<br /><br />Possible values:<ul><li>"sync": Execute expire synchronously. If there are too many files, it may take a long time and block stream processing.</li><li>"async": Execute expire asynchronously. If the generation of snapshots is greater than the deletion, there will be a backlog of files.</li></ul></td>\n        </tr>\n        <tr>\n            <td><h5>snapshot.expire.limit</h5></td>\n            <td style="word-wrap: break-word;">50</td>\n            <td>Integer</td>\n            <td>The maximum number of snapshots allowed to expire at a time.</td>\n        </tr>\n        <tr>\n            <td><h5>snapshot.ignore-empty-commit</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Boolean</td>\n            <td>Whether ignore empty commit.</td>\n        </tr>\n        <tr>\n            <td><h5>snapshot.num-retained.max</h5></td>\n            <td style="word-wrap: break-word;">infinite</td>\n            <td>Integer</td>\n            <td>The maximum number of completed snapshots to retain. Should be greater than or equal to the minimum number.</td>\n        </tr>\n        <tr>\n            <td><h5>snapshot.num-retained.min</h5></td>\n            <td style="word-wrap: break-word;">10</td>\n            <td>Integer</td>\n            <td>The minimum number of completed snapshots to retain. Should be greater than or equal to 1.</td>\n        </tr>\n        <tr>\n            <td><h5>snapshot.time-retained</h5></td>\n            <td style="word-wrap: break-word;">1 h</td>\n            <td>Duration</td>\n            <td>The maximum time of completed snapshots to retain.</td>\n        </tr>\n        <tr>\n            <td><h5>snapshot.watermark-idle-timeout</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Duration</td>\n            <td>In watermarking, if a source remains idle beyond the specified timeout duration, it triggers snapshot advancement and facilitates tag creation.</td>\n        </tr>\n        <tr>\n            <td><h5>sort-compaction.local-sample.magnification</h5></td>\n            <td style="word-wrap: break-word;">1000</td>\n            <td>Integer</td>\n            <td>The magnification of local sample for sort-compaction.The size of local sample is sink parallelism * magnification.</td>\n        </tr>\n        <tr>\n            <td><h5>sort-compaction.range-strategy</h5></td>\n            <td style="word-wrap: break-word;">SIZE</td>\n            <td><p>Enum</p></td>\n            <td>The range strategy of sort compaction, the default value is quantity.\nIf the data size allocated for the sorting task is uneven,which may lead to performance bottlenecks, the config can be set to size.<br /><br />Possible values:<ul><li>"SIZE"</li><li>"QUANTITY"</li></ul></td>\n        </tr>\n        <tr>\n            <td><h5>sort-engine</h5></td>\n            <td style="word-wrap: break-word;">loser-tree</td>\n            <td><p>Enum</p></td>\n            <td>Specify the sort engine for table with primary key.<br /><br />Possible values:<ul><li>"min-heap": Use min-heap for multiway sorting.</li><li>"loser-tree": Use loser-tree for multiway sorting. Compared with heapsort, loser-tree has fewer comparisons and is more efficient.</li></ul></td>\n        </tr>\n        <tr>\n            <td><h5>sort-spill-buffer-size</h5></td>\n            <td style="word-wrap: break-word;">64 mb</td>\n            <td>MemorySize</td>\n            <td>Amount of data to spill records to disk in spilled sort.</td>\n        </tr>\n        <tr>\n            <td><h5>sort-spill-threshold</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Integer</td>\n            <td>If the maximum number of sort readers exceeds this value, a spill will be attempted. This prevents too many readers from consuming too much memory and causing OOM.</td>\n        </tr>\n        <tr>\n            <td><h5>source.split.open-file-cost</h5></td>\n            <td style="word-wrap: break-word;">4 mb</td>\n            <td>MemorySize</td>\n            <td>Open file cost of a source file. It is used to avoid reading too many files with a source split, which can be very slow.</td>\n        </tr>\n        <tr>\n            <td><h5>source.split.target-size</h5></td>\n            <td style="word-wrap: break-word;">128 mb</td>\n            <td>MemorySize</td>\n            <td>Target size of a source split when scanning a bucket.</td>\n        </tr>\n        <tr>\n            <td><h5>spill-compression</h5></td>\n            <td style="word-wrap: break-word;">"zstd"</td>\n            <td>String</td>\n            <td>Compression for spill, currently zstd, lzo and zstd are supported.</td>\n        </tr>\n        <tr>\n            <td><h5>spill-compression.zstd-level</h5></td>\n            <td style="word-wrap: break-word;">1</td>\n            <td>Integer</td>\n            <td>Default spill compression zstd level. For higher compression rates, it can be configured to 9, but the read and write speed will significantly decrease.</td>\n        </tr>\n        <tr>\n            <td><h5>streaming-read-append-overwrite</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether to read the delta from append table\'s overwrite commit in streaming mode.</td>\n        </tr>\n        <tr>\n            <td><h5>streaming-read-overwrite</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether to read the changes from overwrite in streaming mode. Cannot be set to true when changelog producer is full-compaction or lookup because it will read duplicated changes.</td>\n        </tr>\n        <tr>\n            <td><h5>streaming.read.snapshot.delay</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Duration</td>\n            <td>The delay duration of stream read when scan incremental snapshots.</td>\n        </tr>\n        <tr>\n            <td><h5>table-read.sequence-number.enabled</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether to include the _SEQUENCE_NUMBER field when reading the audit_log or binlog system tables. This is only valid for primary key tables.</td>\n        </tr>\n        <tr>\n            <td><h5>tag.automatic-completion</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether to automatically complete missing tags.</td>\n        </tr>\n        <tr>\n            <td><h5>tag.automatic-creation</h5></td>\n            <td style="word-wrap: break-word;">none</td>\n            <td><p>Enum</p></td>\n            <td>Whether to create tag automatically. And how to generate tags.<br /><br />Possible values:<ul><li>"none": No automatically created tags.</li><li>"process-time": Based on the time of the machine, create TAG once the processing time passes period time plus delay.</li><li>"watermark": Based on the watermark of the input, create TAG once the watermark passes period time plus delay.</li><li>"batch": In the batch processing scenario, the tag corresponding to the current snapshot is generated after the task is completed.</li></ul></td>\n        </tr>\n        <tr>\n            <td><h5>tag.batch.customized-name</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>Use customized name when creating tags in Batch mode.</td>\n        </tr>\n        <tr>\n            <td><h5>tag.callback.#.param</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>Parameter string for the constructor of class #. Callback class should parse the parameter by itself.</td>\n        </tr>\n        <tr>\n            <td><h5>tag.callbacks</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>A list of commit callback classes to be called after a successful tag. Class names are connected with comma (example: com.test.CallbackA,com.sample.CallbackB).</td>\n        </tr>\n        <tr>\n            <td><h5>tag.create-success-file</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether to create tag success file for new created tags.</td>\n        </tr>\n        <tr>\n            <td><h5>tag.creation-delay</h5></td>\n            <td style="word-wrap: break-word;">0 ms</td>\n            <td>Duration</td>\n            <td>How long is the delay after the period ends before creating a tag. This can allow some late data to enter the Tag.</td>\n        </tr>\n        <tr>\n            <td><h5>tag.creation-period</h5></td>\n            <td style="word-wrap: break-word;">daily</td>\n            <td><p>Enum</p></td>\n            <td>What frequency is used to generate tags.<br /><br />Possible values:<ul><li>"daily": Generate a tag every day.</li><li>"hourly": Generate a tag every hour.</li><li>"two-hours": Generate a tag every two hours.</li></ul></td>\n        </tr>\n        <tr>\n            <td><h5>tag.creation-period-duration</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Duration</td>\n            <td>The period duration for tag auto create periods.If user set it, tag.creation-period would be invalid.</td>\n        </tr>\n        <tr>\n            <td><h5>tag.default-time-retained</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Duration</td>\n            <td>The default maximum time retained for newly created tags. It affects both auto-created tags and manually created (by procedure) tags.</td>\n        </tr>\n        <tr>\n            <td><h5>tag.num-retained-max</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Integer</td>\n            <td>The maximum number of tags to retain. It only affects auto-created tags.</td>\n        </tr>\n        <tr>\n            <td><h5>tag.period-formatter</h5></td>\n            <td style="word-wrap: break-word;">with_dashes</td>\n            <td><p>Enum</p></td>\n            <td>The date format for tag periods.<br /><br />Possible values:<ul><li>"with_dashes": Dates and hours with dashes, e.g., \'yyyy-MM-dd HH\'</li><li>"without_dashes": Dates and hours without dashes, e.g., \'yyyyMMdd HH\'</li><li>"without_dashes_and_spaces": Dates and hours without dashes and spaces, e.g., \'yyyyMMddHH\'</li></ul></td>\n        </tr>\n        <tr>\n            <td><h5>tag.time-expire-enabled</h5></td>\n            <td style="word-wrap: break-word;">true</td>\n            <td>Boolean</td>\n            <td>Whether to enable tag expiration by retained time.</td>\n        </tr>\n        <tr>\n            <td><h5>target-file-size</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>MemorySize</td>\n            <td>Target size of a file.<ul><li>primary key table: the default value is 128 MB.</li><li>append table: the default value is 256 MB.</li></ul></td>\n        </tr>\n        <tr>\n            <td><h5>type</h5></td>\n            <td style="word-wrap: break-word;">table</td>\n            <td><p>Enum</p></td>\n            <td>Type of the table.<br /><br />Possible values:<ul><li>"table": Normal Paimon table.</li><li>"format-table": A file format table refers to a directory that contains multiple files of the same format.</li><li>"materialized-table": A materialized table combines normal Paimon table and materialized SQL.</li><li>"object-table": An object table combines normal Paimon table and object location.</li><li>"lance-table": A lance table, see \'https://lancedb.github.io/lance/\'.</li><li>"iceberg-table": An iceberg table, see \'https://iceberg.apache.org/\'.</li></ul></td>\n        </tr>\n        <tr>\n            <td><h5>upsert-key</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>Define upsert key to do MERGE INTO when executing INSERT INTO, cannot be defined with primary key.</td>\n        </tr>\n        <tr>\n            <td><h5>variant.inferShreddingSchema</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether to automatically infer the shredding schema when writing Variant columns.</td>\n        </tr>\n        <tr>\n            <td><h5>variant.shredding.maxInferBufferRow</h5></td>\n            <td style="word-wrap: break-word;">4096</td>\n            <td>Integer</td>\n            <td>Maximum number of rows to buffer for schema inference.</td>\n        </tr>\n        <tr>\n            <td><h5>variant.shredding.maxSchemaDepth</h5></td>\n            <td style="word-wrap: break-word;">50</td>\n            <td>Integer</td>\n            <td>Maximum traversal depth in Variant values during schema inference.</td>\n        </tr>\n        <tr>\n            <td><h5>variant.shredding.maxSchemaWidth</h5></td>\n            <td style="word-wrap: break-word;">300</td>\n            <td>Integer</td>\n            <td>Maximum number of shredded fields allowed in an inferred schema.</td>\n        </tr>\n        <tr>\n            <td><h5>variant.shredding.minFieldCardinalityRatio</h5></td>\n            <td style="word-wrap: break-word;">0.1</td>\n            <td>Double</td>\n            <td>Minimum fraction of rows that must contain a field for it to be shredded. Fields below this threshold will remain in the un-shredded Variant binary.</td>\n        </tr>\n        <tr>\n            <td><h5>variant.shreddingSchema</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>The Variant shredding schema for writing.</td>\n        </tr>\n        <tr>\n            <td><h5>vector-field</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>Specifies column names that should be stored as vector type. This is used when you want to treat a ARRAY column as a VECTOR.</td>\n        </tr>\n        <tr>\n            <td><h5>vector-search.distribute.enabled</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether to process distributed vector search.</td>\n        </tr>\n        <tr>\n            <td><h5>vector-search.lateral-join.batch-size</h5></td>\n            <td style="word-wrap: break-word;">256</td>\n            <td>Integer</td>\n            <td>The batch size for lateral vector search. Each batch executes vector topK search and table lookup for multiple query vectors.</td>\n        </tr>\n        <tr>\n            <td><h5>vector.file.format</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>Specify the vector store file format.</td>\n        </tr>\n        <tr>\n            <td><h5>vector.target-file-size</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>MemorySize</td>\n            <td>Target size of a vector-store file. Default is the same as TARGET_FILE_SIZE.</td>\n        </tr>\n        <tr>\n            <td><h5>visibility-callback.check-interval</h5></td>\n            <td style="word-wrap: break-word;">10 s</td>\n            <td>Duration</td>\n            <td>The interval for checking visibility when visibility-callback enabled.</td>\n        </tr>\n        <tr>\n            <td><h5>visibility-callback.enabled</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether to enable the visibility wait callback that waits for compaction or global index build to complete after commit. This is useful for primary key tables with deletion vectors or postpone bucket mode and row-tracking tables with global indexes to ensure data visibility, only used for batch mode or bounded stream.</td>\n        </tr>\n        <tr>\n            <td><h5>visibility-callback.timeout</h5></td>\n            <td style="word-wrap: break-word;">30 min</td>\n            <td>Duration</td>\n            <td>The maximum time to wait for compaction or global index build to complete when visibility callback is enabled. If the timeout is reached, an exception will be thrown.</td>\n        </tr>\n        <tr>\n            <td><h5>write-buffer-for-append</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>This option only works for append-only table. Whether the write use write buffer to avoid out-of-memory error.</td>\n        </tr>\n        <tr>\n            <td><h5>write-buffer-size</h5></td>\n            <td style="word-wrap: break-word;">256 mb</td>\n            <td>MemorySize</td>\n            <td>Amount of data to build up in memory before converting to a sorted on-disk file.</td>\n        </tr>\n        <tr>\n            <td><h5>write-buffer-spill.max-disk-size</h5></td>\n            <td style="word-wrap: break-word;">infinite</td>\n            <td>MemorySize</td>\n            <td>The max disk to use for write buffer spill. This only work when the write buffer spill is enabled</td>\n        </tr>\n        <tr>\n            <td><h5>write-buffer-spillable</h5></td>\n            <td style="word-wrap: break-word;">true</td>\n            <td>Boolean</td>\n            <td>Whether the write buffer can be spillable.</td>\n        </tr>\n        <tr>\n            <td><h5>write-max-writers-to-spill</h5></td>\n            <td style="word-wrap: break-word;">10</td>\n            <td>Integer</td>\n            <td>When in batch append inserting, if the writer number is greater than this option, we open the buffer cache and spill function to avoid out-of-memory. </td>\n        </tr>\n        <tr>\n            <td><h5>write-only</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>If set to true, compactions and snapshot expiration will be skipped. This option is used along with dedicated compact jobs.</td>\n        </tr>\n        <tr>\n            <td><h5>write.batch-memory</h5></td>\n            <td style="word-wrap: break-word;">128 mb</td>\n            <td>MemorySize</td>\n            <td>Write batch memory for any file format if it supports.</td>\n        </tr>\n        <tr>\n            <td><h5>write.batch-size</h5></td>\n            <td style="word-wrap: break-word;">1024</td>\n            <td>Integer</td>\n            <td>Write batch size for any file format if it supports.</td>\n        </tr>\n        <tr>\n            <td><h5>write.sequence-number-init-mode</h5></td>\n            <td style="word-wrap: break-word;">scan</td>\n            <td><p>Enum</p></td>\n            <td>Specify how to initialize the next sequence number for primary key table writers.<br /><br />Possible values:<ul><li>"scan": initialize by scanning existing file metadata.</li><li>"snapshot": initialize from the maximum sequence number recorded in snapshot properties, which can avoid scanning existing file metadata in write-only mode.</li></ul></td>\n        </tr>\n        <tr>\n            <td><h5>zorder.var-length-contribution</h5></td>\n            <td style="word-wrap: break-word;">8</td>\n            <td>Integer</td>\n            <td>The bytes of types (CHAR, VARCHAR, BINARY, VARBINARY) devote to the zorder sort.</td>\n        </tr>\n    </tbody>\n</table>\n'}),"\n",(0,d.jsx)(e.h3,{id:"catalogoptions",children:"CatalogOptions"}),"\n",(0,d.jsx)(e.p,{children:"Options for paimon catalog."}),"\n",(0,d.jsx)(o.A,{html:'\x3c!--\nLicensed to the Apache Software Foundation (ASF) under one\nor more contributor license agreements.  See the NOTICE file\ndistributed with this work for additional information\nregarding copyright ownership.  The ASF licenses this file\nto you under the Apache License, Version 2.0 (the\n"License"); you may not use this file except in compliance\nwith the License.  You may obtain a copy of the License at\n\n  http://www.apache.org/licenses/LICENSE-2.0\n\nUnless required by applicable law or agreed to in writing,\nsoftware distributed under the License is distributed on an\n"AS IS" BASIS, WITHOUT WARRANTIES OR CONDITIONS OF ANY\nKIND, either express or implied.  See the License for the\nspecific language governing permissions and limitations\nunder the License.\n--\x3e\n<table class="configuration table table-bordered">\n    <thead>\n        <tr>\n            <th class="text-left" style="width: 20%">Key</th>\n            <th class="text-left" style="width: 15%">Default</th>\n            <th class="text-left" style="width: 10%">Type</th>\n            <th class="text-left" style="width: 55%">Description</th>\n        </tr>\n    </thead>\n    <tbody>\n        <tr>\n            <td><h5>cache-enabled</h5></td>\n            <td style="word-wrap: break-word;">true</td>\n            <td>Boolean</td>\n            <td>Controls whether the catalog will cache databases, tables, manifests and partitions.</td>\n        </tr>\n        <tr>\n            <td><h5>cache.deletion-vectors.max-num</h5></td>\n            <td style="word-wrap: break-word;">100000</td>\n            <td>Integer</td>\n            <td>Controls the maximum number of deletion vector meta that can be cached.</td>\n        </tr>\n        <tr>\n            <td><h5>cache.expire-after-access</h5></td>\n            <td style="word-wrap: break-word;">10 min</td>\n            <td>Duration</td>\n            <td>Cache expiration policy: marks cache entries to expire after a specified duration has passed since their last access.</td>\n        </tr>\n        <tr>\n            <td><h5>cache.expire-after-write</h5></td>\n            <td style="word-wrap: break-word;">30 min</td>\n            <td>Duration</td>\n            <td>Cache expiration policy: marks cache entries to expire after a specified duration has passed since their last refresh.</td>\n        </tr>\n        <tr>\n            <td><h5>cache.manifest.max-memory</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>MemorySize</td>\n            <td>Controls the maximum memory to cache manifest content.</td>\n        </tr>\n        <tr>\n            <td><h5>cache.manifest.small-file-memory</h5></td>\n            <td style="word-wrap: break-word;">128 mb</td>\n            <td>MemorySize</td>\n            <td>Controls the cache memory to cache small manifest files.</td>\n        </tr>\n        <tr>\n            <td><h5>cache.manifest.small-file-threshold</h5></td>\n            <td style="word-wrap: break-word;">1 mb</td>\n            <td>MemorySize</td>\n            <td>Controls the threshold of small manifest file.</td>\n        </tr>\n        <tr>\n            <td><h5>cache.manifest.soft-values</h5></td>\n            <td style="word-wrap: break-word;">true</td>\n            <td>Boolean</td>\n            <td>If true (default), manifest cache entries are held with soft references and may be reclaimed by the GC under memory pressure. This can trigger a cache-thrash spiral where reclaimed entries are refetched, spiking heap and forcing further reclamation. Set to false to hold entries with strong references, breaking the spiral; the cache then stays bounded by weight up to \'cache.manifest.max-memory\' (size the total heap memory to at least roughly twice that value).</td>\n        </tr>\n        <tr>\n            <td><h5>cache.partition.max-num</h5></td>\n            <td style="word-wrap: break-word;">0</td>\n            <td>Long</td>\n            <td>Controls the max number for which partitions in the catalog are cached.</td>\n        </tr>\n        <tr>\n            <td><h5>cache.snapshot.max-num-per-table</h5></td>\n            <td style="word-wrap: break-word;">20</td>\n            <td>Integer</td>\n            <td>Controls the max number for snapshots per table in the catalog are cached.</td>\n        </tr>\n        <tr>\n            <td><h5>case-sensitive</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Boolean</td>\n            <td>Indicates whether this catalog is case-sensitive.</td>\n        </tr>\n        <tr>\n            <td><h5>catalog-options-table.enabled</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether to support the sys.catalog_options table.</td>\n        </tr>\n        <tr>\n            <td><h5>client-pool-size</h5></td>\n            <td style="word-wrap: break-word;">2</td>\n            <td>Integer</td>\n            <td>Configure the size of the connection pool.</td>\n        </tr>\n        <tr>\n            <td><h5>file-io.allow-cache</h5></td>\n            <td style="word-wrap: break-word;">true</td>\n            <td>Boolean</td>\n            <td>Whether to allow static cache in file io implementation. If not allowed, this means that there may be a large number of FileIO instances generated, enabling caching can lead to resource leakage.</td>\n        </tr>\n        <tr>\n            <td><h5>format-table.enabled</h5></td>\n            <td style="word-wrap: break-word;">true</td>\n            <td>Boolean</td>\n            <td>Whether to support format tables, format table corresponds to a regular csv, parquet or orc table, allowing read and write operations. However, during these processes, it does not connect to the metastore; hence, newly added partitions will not be reflected in the metastore and need to be manually added as separate partition operations.</td>\n        </tr>\n        <tr>\n            <td><h5>local-cache.block-size</h5></td>\n            <td style="word-wrap: break-word;">1 mb</td>\n            <td>MemorySize</td>\n            <td>Block size for local cache.</td>\n        </tr>\n        <tr>\n            <td><h5>local-cache.dir</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>Directory for local block cache on disk. If not configured, memory cache is used instead.</td>\n        </tr>\n        <tr>\n            <td><h5>local-cache.enabled</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether to enable local block cache for file reads. If local-cache.dir is configured, disk cache is used; otherwise memory cache is used.</td>\n        </tr>\n        <tr>\n            <td><h5>local-cache.max-size</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>MemorySize</td>\n            <td>Maximum total size of the local block cache. Unlimited by default.</td>\n        </tr>\n        <tr>\n            <td><h5>local-cache.whitelist</h5></td>\n            <td style="word-wrap: break-word;">"meta,global-index"</td>\n            <td>String</td>\n            <td>Comma-separated list of file types to cache. Supported values: meta, global-index, bucket-index, data, file-index.</td>\n        </tr>\n        <tr>\n            <td><h5>lock-acquire-timeout</h5></td>\n            <td style="word-wrap: break-word;">8 min</td>\n            <td>Duration</td>\n            <td>The maximum time to wait for acquiring the lock.</td>\n        </tr>\n        <tr>\n            <td><h5>lock-check-max-sleep</h5></td>\n            <td style="word-wrap: break-word;">8 s</td>\n            <td>Duration</td>\n            <td>The maximum sleep time when retrying to check the lock.</td>\n        </tr>\n        <tr>\n            <td><h5>lock.enabled</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Boolean</td>\n            <td>Enable Catalog Lock.</td>\n        </tr>\n        <tr>\n            <td><h5>lock.type</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>The Lock Type for Catalog, such as \'hive\', \'zookeeper\'.</td>\n        </tr>\n        <tr>\n            <td><h5>metastore</h5></td>\n            <td style="word-wrap: break-word;">"filesystem"</td>\n            <td>String</td>\n            <td>Metastore of paimon catalog, supports filesystem, hive and jdbc.</td>\n        </tr>\n        <tr>\n            <td><h5>resolving-file-io.enabled</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether to enable resolving fileio, when this option is enabled, in conjunction with the table\'s property data-file.external-paths, Paimon can read and write to external storage paths, such as OSS or S3. In order to access these external paths correctly, you also need to configure the corresponding access key and secret key.</td>\n        </tr>\n        <tr>\n            <td><h5>sync-all-properties</h5></td>\n            <td style="word-wrap: break-word;">true</td>\n            <td>Boolean</td>\n            <td>Sync all table properties to the catalog metastore (e.g. Hive metastore, JDBC catalog store)</td>\n        </tr>\n        <tr>\n            <td><h5>table.type</h5></td>\n            <td style="word-wrap: break-word;">managed</td>\n            <td><p>Enum</p></td>\n            <td>Type of table.<br /><br />Possible values:<ul><li>"managed": Paimon owned table where the entire lifecycle of the table data is managed.</li><li>"external": The table where Paimon has loose coupling with the data stored in external locations.</li></ul></td>\n        </tr>\n        <tr>\n            <td><h5>uri</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>Uri of metastore server.</td>\n        </tr>\n        <tr>\n            <td><h5>warehouse</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>The warehouse root path of catalog.</td>\n        </tr>\n    </tbody>\n</table>\n'}),"\n",(0,d.jsx)(e.h3,{id:"hivecatalogoptions",children:"HiveCatalogOptions"}),"\n",(0,d.jsx)(e.p,{children:"Options for Hive catalog."}),"\n",(0,d.jsx)(o.A,{html:'\x3c!--\nLicensed to the Apache Software Foundation (ASF) under one\nor more contributor license agreements.  See the NOTICE file\ndistributed with this work for additional information\nregarding copyright ownership.  The ASF licenses this file\nto you under the Apache License, Version 2.0 (the\n"License"); you may not use this file except in compliance\nwith the License.  You may obtain a copy of the License at\n\n  http://www.apache.org/licenses/LICENSE-2.0\n\nUnless required by applicable law or agreed to in writing,\nsoftware distributed under the License is distributed on an\n"AS IS" BASIS, WITHOUT WARRANTIES OR CONDITIONS OF ANY\nKIND, either express or implied.  See the License for the\nspecific language governing permissions and limitations\nunder the License.\n--\x3e\n<table class="configuration table table-bordered">\n    <thead>\n        <tr>\n            <th class="text-left" style="width: 20%">Key</th>\n            <th class="text-left" style="width: 15%">Default</th>\n            <th class="text-left" style="width: 10%">Type</th>\n            <th class="text-left" style="width: 55%">Description</th>\n        </tr>\n    </thead>\n    <tbody>\n        <tr>\n            <td><h5>alter-table-cascade</h5></td>\n            <td style="word-wrap: break-word;">true</td>\n            <td>Boolean</td>\n            <td>Whether to cascade schema changes to Hive metastore partitions when altering table.</td>\n        </tr>\n        <tr>\n            <td><h5>client-pool-cache.eviction-interval-ms</h5></td>\n            <td style="word-wrap: break-word;">300000</td>\n            <td>Long</td>\n            <td>Setting the client\'s pool cache eviction interval(ms).\n</td>\n        </tr>\n        <tr>\n            <td><h5>client-pool-cache.keys</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>Specify client cache key, multiple elements separated by commas.<br /><ul><li>"ugi":  the Hadoop UserGroupInformation instance that represents the current user using the cache.</li></ul><ul><li>"user_name" similar to UGI but only includes the user\'s name determined by UserGroupInformation#getUserName.</li></ul><ul><li>"conf": name of an arbitrary configuration. The value of the configuration will be extracted from catalog properties and added to the cache key. A conf element should start with a "conf:" prefix which is followed by the configuration name. E.g. specifying "conf:a.b.c" will add "a.b.c" to the key, and so that configurations with different default catalog wouldn\'t share the same client pool. Multiple conf elements can be specified.</li></ul></td>\n        </tr>\n        <tr>\n            <td><h5>hadoop-conf-dir</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>File directory of the core-site.xml\u3001hdfs-site.xml\u3001yarn-site.xml\u3001mapred-site.xml. Currently, only local file system paths are supported.\nIf not configured, try to load from \'HADOOP_CONF_DIR\' or \'HADOOP_HOME\' system environment.\nConfigure Priority: 1.from \'hadoop-conf-dir\' 2.from HADOOP_CONF_DIR  3.from HADOOP_HOME/conf 4.HADOOP_HOME/etc/hadoop.\n</td>\n        </tr>\n        <tr>\n            <td><h5>hive-conf-dir</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>File directory of the hive-site.xml , used to create HiveMetastoreClient and security authentication, such as Kerberos, LDAP, Ranger and so on.\nIf not configured, try to load from \'HIVE_CONF_DIR\' env.\n</td>\n        </tr>\n        <tr>\n            <td><h5>hive.skip-update-stats</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>If true, sets DO_NOT_UPDATE_STATS in the Hive EnvironmentContext when altering tables, preventing Hive from updating table statistics.</td>\n        </tr>\n        <tr>\n            <td><h5>location-in-properties</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Setting the location in properties of hive table/database.\nIf you don\'t want to access the location by the filesystem of hive when using a object storage such as s3,oss\nyou can set this option to true.\n</td>\n        </tr>\n        <tr>\n            <td><h5>metastore.client.class</h5></td>\n            <td style="word-wrap: break-word;">"org.apache.hadoop.hive.metastore.HiveMetaStoreClient"</td>\n            <td>String</td>\n            <td>Class name of Hive metastore client.\nNOTE: This class must directly implements org.apache.hadoop.hive.metastore.IMetaStoreClient.</td>\n        </tr>\n    </tbody>\n</table>\n'}),"\n",(0,d.jsx)(e.h3,{id:"hiveconnectoroptions",children:"HiveConnectorOptions"}),"\n",(0,d.jsx)(e.p,{children:"Hive connector options for paimon."}),"\n",(0,d.jsx)(o.A,{html:'\x3c!--\nLicensed to the Apache Software Foundation (ASF) under one\nor more contributor license agreements.  See the NOTICE file\ndistributed with this work for additional information\nregarding copyright ownership.  The ASF licenses this file\nto you under the Apache License, Version 2.0 (the\n"License"); you may not use this file except in compliance\nwith the License.  You may obtain a copy of the License at\n\n  http://www.apache.org/licenses/LICENSE-2.0\n\nUnless required by applicable law or agreed to in writing,\nsoftware distributed under the License is distributed on an\n"AS IS" BASIS, WITHOUT WARRANTIES OR CONDITIONS OF ANY\nKIND, either express or implied.  See the License for the\nspecific language governing permissions and limitations\nunder the License.\n--\x3e\n<table class="configuration table table-bordered">\n    <thead>\n        <tr>\n            <th class="text-left" style="width: 20%">Key</th>\n            <th class="text-left" style="width: 15%">Default</th>\n            <th class="text-left" style="width: 10%">Type</th>\n            <th class="text-left" style="width: 55%">Description</th>\n        </tr>\n    </thead>\n    <tbody>\n        <tr>\n            <td><h5>paimon.respect.minmaxsplitsize.enabled</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>If true, Paimon will calculate the size of split through hive parameters about splits such as \'mapreduce.input.fileinputformat.split.minsize\' and \'mapreduce.input.fileinputformat.split.maxsize\', and then split.</td>\n        </tr>\n        <tr>\n            <td><h5>paimon.split.openfilecost</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Long</td>\n            <td>The cost when open a file. The config will overwrite the table property \'source.split.open-file-cost\'.</td>\n        </tr>\n    </tbody>\n</table>\n'}),"\n",(0,d.jsx)(e.h3,{id:"jdbccatalogoptions",children:"JdbcCatalogOptions"}),"\n",(0,d.jsx)(e.p,{children:"Options for Jdbc catalog."}),"\n",(0,d.jsx)(o.A,{html:'\x3c!--\nLicensed to the Apache Software Foundation (ASF) under one\nor more contributor license agreements.  See the NOTICE file\ndistributed with this work for additional information\nregarding copyright ownership.  The ASF licenses this file\nto you under the Apache License, Version 2.0 (the\n"License"); you may not use this file except in compliance\nwith the License.  You may obtain a copy of the License at\n\n  http://www.apache.org/licenses/LICENSE-2.0\n\nUnless required by applicable law or agreed to in writing,\nsoftware distributed under the License is distributed on an\n"AS IS" BASIS, WITHOUT WARRANTIES OR CONDITIONS OF ANY\nKIND, either express or implied.  See the License for the\nspecific language governing permissions and limitations\nunder the License.\n--\x3e\n<table class="configuration table table-bordered">\n    <thead>\n        <tr>\n            <th class="text-left" style="width: 20%">Key</th>\n            <th class="text-left" style="width: 15%">Default</th>\n            <th class="text-left" style="width: 10%">Type</th>\n            <th class="text-left" style="width: 55%">Description</th>\n        </tr>\n    </thead>\n    <tbody>\n        <tr>\n            <td><h5>catalog-key</h5></td>\n            <td style="word-wrap: break-word;">"jdbc"</td>\n            <td>String</td>\n            <td>Custom jdbc catalog store key.</td>\n        </tr>\n        <tr>\n            <td><h5>lock-key-max-length</h5></td>\n            <td style="word-wrap: break-word;">255</td>\n            <td>Integer</td>\n            <td>Set the maximum length of the lock key. The \'lock-key\' is composed of concatenating three fields : \'catalog-key\', \'database\', and \'table\'.</td>\n        </tr>\n    </tbody>\n</table>\n'}),"\n",(0,d.jsx)(e.h3,{id:"flinkcatalogoptions",children:"FlinkCatalogOptions"}),"\n",(0,d.jsx)(e.p,{children:"Flink catalog options for paimon."}),"\n",(0,d.jsx)(o.A,{html:'\x3c!--\nLicensed to the Apache Software Foundation (ASF) under one\nor more contributor license agreements.  See the NOTICE file\ndistributed with this work for additional information\nregarding copyright ownership.  The ASF licenses this file\nto you under the Apache License, Version 2.0 (the\n"License"); you may not use this file except in compliance\nwith the License.  You may obtain a copy of the License at\n\n  http://www.apache.org/licenses/LICENSE-2.0\n\nUnless required by applicable law or agreed to in writing,\nsoftware distributed under the License is distributed on an\n"AS IS" BASIS, WITHOUT WARRANTIES OR CONDITIONS OF ANY\nKIND, either express or implied.  See the License for the\nspecific language governing permissions and limitations\nunder the License.\n--\x3e\n<table class="configuration table table-bordered">\n    <thead>\n        <tr>\n            <th class="text-left" style="width: 20%">Key</th>\n            <th class="text-left" style="width: 15%">Default</th>\n            <th class="text-left" style="width: 10%">Type</th>\n            <th class="text-left" style="width: 55%">Description</th>\n        </tr>\n    </thead>\n    <tbody>\n        <tr>\n            <td><h5>default-database</h5></td>\n            <td style="word-wrap: break-word;">"default"</td>\n            <td>String</td>\n            <td></td>\n        </tr>\n        <tr>\n            <td><h5>disable-create-table-in-default-db</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>If true, creating table in default database is not allowed. Default is false.</td>\n        </tr>\n        <tr>\n            <td><h5>lineage-use-catalog-key-as-identifier</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether to use the \'catalog-key\' as the catalog identifier in the lineage dataset name (i.e., catalog_key.db_name.table_name) when using a JDBC metastore. If false, the internal Flink catalog name is used instead.</td>\n        </tr>\n    </tbody>\n</table>\n'}),"\n",(0,d.jsx)(e.h3,{id:"flinkconnectoroptions",children:"FlinkConnectorOptions"}),"\n",(0,d.jsx)(e.p,{children:"Flink connector options for paimon."}),"\n",(0,d.jsx)(o.A,{html:'\x3c!--\nLicensed to the Apache Software Foundation (ASF) under one\nor more contributor license agreements.  See the NOTICE file\ndistributed with this work for additional information\nregarding copyright ownership.  The ASF licenses this file\nto you under the Apache License, Version 2.0 (the\n"License"); you may not use this file except in compliance\nwith the License.  You may obtain a copy of the License at\n\n  http://www.apache.org/licenses/LICENSE-2.0\n\nUnless required by applicable law or agreed to in writing,\nsoftware distributed under the License is distributed on an\n"AS IS" BASIS, WITHOUT WARRANTIES OR CONDITIONS OF ANY\nKIND, either express or implied.  See the License for the\nspecific language governing permissions and limitations\nunder the License.\n--\x3e\n<table class="configuration table table-bordered">\n    <thead>\n        <tr>\n            <th class="text-left" style="width: 20%">Key</th>\n            <th class="text-left" style="width: 15%">Default</th>\n            <th class="text-left" style="width: 10%">Type</th>\n            <th class="text-left" style="width: 55%">Description</th>\n        </tr>\n    </thead>\n    <tbody>\n        <tr>\n            <td><h5>compaction.bucket-distribution-strategy</h5></td>\n            <td style="word-wrap: break-word;">linear</td>\n            <td><p>Enum</p></td>\n            <td>Defines how dedicated bucket compaction jobs distribute compact buckets to writers. \'linear\' uses the existing stable partition-plus-bucket mapping. \'size-aware-batch\' assigns bounded full-compaction bucket splits by total data file size and forwards them to writers to reduce compaction long tail.<br /><br />Possible values:<ul><li>"linear": Distribute compact buckets by the existing stable partition-plus-bucket channel mapping.</li><li>"size-aware-batch": For bounded full compaction, assign compact bucket splits by total data file size and forward them to writers to reduce long-tail compaction tasks.</li></ul></td>\n        </tr>\n        <tr>\n            <td><h5>changelog.precommit-compact.thread-num</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Integer</td>\n            <td>Maximum number of threads to copy bytes from small changelog files. By default is the number of processors available to the Java virtual machine.</td>\n        </tr>\n        <tr>\n            <td><h5>commit.custom-listeners</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>Commit listener will be called after a successful commit. This option list custom commit listener identifiers separated by comma.</td>\n        </tr>\n        <tr>\n            <td><h5>end-input.watermark</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Long</td>\n            <td>Optional endInput watermark used in case of batch mode or bounded stream.</td>\n        </tr>\n        <tr>\n            <td><h5>filesystem.job-level-settings.enabled</h5></td>\n            <td style="word-wrap: break-word;">true</td>\n            <td>Boolean</td>\n            <td>Enable pass job level filesystem settings to table file IO.</td>\n        </tr>\n        <tr>\n            <td><h5>lookup.async</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether to enable async lookup join.</td>\n        </tr>\n        <tr>\n            <td><h5>lookup.async-thread-number</h5></td>\n            <td style="word-wrap: break-word;">16</td>\n            <td>Integer</td>\n            <td>The thread number for lookup async.</td>\n        </tr>\n        <tr>\n            <td><h5>lookup.bootstrap-parallelism</h5></td>\n            <td style="word-wrap: break-word;">4</td>\n            <td>Integer</td>\n            <td>The parallelism for bootstrap in a single task for lookup join.</td>\n        </tr>\n        <tr>\n            <td><h5>lookup.cache</h5></td>\n            <td style="word-wrap: break-word;">AUTO</td>\n            <td><p>Enum</p></td>\n            <td>The cache mode of lookup join.<br /><br />Possible values:<ul><li>"AUTO"</li><li>"FULL"</li><li>"MEMORY"</li></ul></td>\n        </tr>\n        <tr>\n            <td><h5>lookup.dynamic-partition.refresh-interval</h5></td>\n            <td style="word-wrap: break-word;">1 h</td>\n            <td>Duration</td>\n            <td>Specific dynamic partition refresh interval for lookup, scan all partitions and obtain corresponding partition.</td>\n        </tr>\n        <tr>\n            <td><h5>lookup.dynamic-partition.refresh.async</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether to refresh dynamic partition lookup table asynchronously. This option only works for full cache dimension table. When enabled, partition changes will be loaded in a background thread while the old partition data continues serving queries. When disabled (default), partition refresh is synchronous and blocks queries until the new partition data is fully loaded.</td>\n        </tr>\n        <tr>\n            <td><h5>lookup.refresh.async</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether to refresh lookup table in an async thread.</td>\n        </tr>\n        <tr>\n            <td><h5>lookup.refresh.async.pending-snapshot-count</h5></td>\n            <td style="word-wrap: break-word;">5</td>\n            <td>Integer</td>\n            <td>If the pending snapshot count exceeds the threshold, lookup operator will refresh the table in sync.</td>\n        </tr>\n        <tr>\n            <td><h5>lookup.refresh.full-load-threshold</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Integer</td>\n            <td>If the pending snapshot count exceeds this threshold, lookup table will discard incremental updates and refresh the entire table from the latest snapshot. This can improve performance when there are many snapshots pending. Set to a reasonable value (e.g., 10) to enable this optimization. Default is Integer.MAX_VALUE (disabled). </td>\n        </tr>\n        <tr>\n            <td><h5>lookup.refresh.time-periods-blacklist</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>The blacklist contains several time periods. During these time periods, the lookup table\'s cache refreshing is forbidden. Blacklist format is start1-&gt;end1,start2-&gt;end2,... , and the time format is yyyy-MM-dd HH:mm. Only used when lookup table is FULL cache mode.</td>\n        </tr>\n        <tr>\n            <td><h5>partition.idle-time-to-done</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Duration</td>\n            <td>Set a time duration when a partition has no new data after this time duration, mark the done status to indicate that the data is ready.</td>\n        </tr>\n        <tr>\n            <td><h5>partition.mark-done-action.mode</h5></td>\n            <td style="word-wrap: break-word;">process-time</td>\n            <td><p>Enum</p></td>\n            <td>How to trigger partition mark done action.<br /><br />Possible values:<ul><li>"process-time": Based on the time of the machine, mark the partition done once the processing time passes period time plus delay.</li><li>"watermark": Based on the watermark of the input, mark the partition done once the watermark passes period time plus delay.</li></ul></td>\n        </tr>\n        <tr>\n            <td><h5>partition.mark-done.recover-from-state</h5></td>\n            <td style="word-wrap: break-word;">true</td>\n            <td>Boolean</td>\n            <td>Whether trigger partition mark done when recover from state.</td>\n        </tr>\n        <tr>\n            <td><h5>partition.time-interval</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Duration</td>\n            <td>You can specify time interval for partition, for example, daily partition is \'1 d\', hourly partition is \'1 h\'.</td>\n        </tr>\n        <tr>\n            <td><h5>precommit-compact</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>If true, it will add a compact coordinator and worker operator after the writer operator,in order to compact several changelog files (for primary key tables) or newly created data files (for unaware bucket tables) from the same partition into large ones, which can decrease the number of small files.</td>\n        </tr>\n        <tr>\n            <td><h5>read.shuffle-bucket-with-partition</h5></td>\n            <td style="word-wrap: break-word;">true</td>\n            <td>Boolean</td>\n            <td>Whether shuffle by partition and bucket when read.</td>\n        </tr>\n        <tr>\n            <td><h5>scan.bounded</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Boolean</td>\n            <td>Bounded mode for Paimon consumer. By default, Paimon automatically selects bounded mode based on the mode of the Flink job.</td>\n        </tr>\n        <tr>\n            <td><h5>scan.dedicated-split-generation</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>If true, the split generation process would be performed during runtime on a Flink task, instead of on the JobManager during initialization phase.</td>\n        </tr>\n        <tr>\n            <td><h5>scan.infer-parallelism</h5></td>\n            <td style="word-wrap: break-word;">true</td>\n            <td>Boolean</td>\n            <td>If it is false, parallelism of source are set by global parallelism. Otherwise, source parallelism is inferred from splits number (batch mode) or bucket number(streaming mode).</td>\n        </tr>\n        <tr>\n            <td><h5>scan.infer-parallelism.max</h5></td>\n            <td style="word-wrap: break-word;">1024</td>\n            <td>Integer</td>\n            <td>If scan.infer-parallelism is true, limit the parallelism of source through this option.</td>\n        </tr>\n        <tr>\n            <td><h5>scan.max-snapshot.count</h5></td>\n            <td style="word-wrap: break-word;">-1</td>\n            <td>Integer</td>\n            <td>The max snapshot count to scan per checkpoint. Not limited when it\'s negative.</td>\n        </tr>\n        <tr>\n            <td><h5>scan.parallelism</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Integer</td>\n            <td>Define a custom parallelism for the scan source. By default, if this option is not defined, the planner will derive the parallelism for each statement individually by also considering the global configuration. If user enable the scan.infer-parallelism, the planner will derive the parallelism by inferred parallelism.</td>\n        </tr>\n        <tr>\n            <td><h5>scan.partitions</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>Specify the partitions to scan. Partitions should be given in the form of key1=value1,key2=value2. Partition keys not specified will be filled with the value of partition.default-name. Multiple partitions should be separated by semicolon (;). This option can support normal source tables and lookup join tables. There are two special values max_pt() and max_two_pt() are also supported to specify the (two) partition(s) with the largest partition value. For lookup source, the max partition(s) will be periodically refreshed; for normal source, the max partition(s) will be determined before job running without refreshing even for streaming jobs.</td>\n        </tr>\n        <tr>\n            <td><h5>scan.remove-normalize</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether to force the removal of the normalize node when streaming read. Note: This is dangerous and is likely to cause data errors if downstream is used to calculate aggregation and the input is not complete changelog.</td>\n        </tr>\n        <tr>\n            <td><h5>scan.split-enumerator.batch-size</h5></td>\n            <td style="word-wrap: break-word;">10</td>\n            <td>Integer</td>\n            <td>How many splits should assign to subtask per batch in StaticFileStoreSplitEnumerator to avoid exceed `akka.framesize` limit.</td>\n        </tr>\n        <tr>\n            <td><h5>scan.split-enumerator.mode</h5></td>\n            <td style="word-wrap: break-word;">fair</td>\n            <td><p>Enum</p></td>\n            <td>The mode used by StaticFileStoreSplitEnumerator to assign splits.<br /><br />Possible values:<ul><li>"fair": Distribute splits evenly when batch reading to prevent a few tasks from reading all.</li><li>"preemptive": Distribute splits preemptively according to the consumption speed of the task.</li></ul></td>\n        </tr>\n        <tr>\n            <td><h5>scan.watermark.alignment.group</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>A group of sources to align watermarks.</td>\n        </tr>\n        <tr>\n            <td><h5>scan.watermark.alignment.max-drift</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Duration</td>\n            <td>Maximal drift to align watermarks, before we pause consuming from the source/task/partition.</td>\n        </tr>\n        <tr>\n            <td><h5>scan.watermark.alignment.update-interval</h5></td>\n            <td style="word-wrap: break-word;">1 s</td>\n            <td>Duration</td>\n            <td>How often tasks should notify coordinator about the current watermark and how often the coordinator should announce the maximal aligned watermark.</td>\n        </tr>\n        <tr>\n            <td><h5>scan.watermark.emit.strategy</h5></td>\n            <td style="word-wrap: break-word;">on-event</td>\n            <td><p>Enum</p></td>\n            <td>Emit strategy for watermark generation.<br /><br />Possible values:<ul><li>"on-periodic": Emit watermark periodically, interval is controlled by Flink \'pipeline.auto-watermark-interval\'.</li><li>"on-event": Emit watermark per record.</li></ul></td>\n        </tr>\n        <tr>\n            <td><h5>scan.watermark.idle-timeout</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Duration</td>\n            <td>If no records flow in a partition of a stream for that amount of time, then that partition is considered "idle" and will not hold back the progress of watermarks in downstream operators.</td>\n        </tr>\n        <tr>\n            <td><h5>sink.clustering.sample-factor</h5></td>\n            <td style="word-wrap: break-word;">100</td>\n            <td>Integer</td>\n            <td>Specifies the sample factor. Let S represent the total number of samples, F represent the sample factor, and P represent the sink parallelism, then S=F\xd7P. The minimum allowed sample factor is 20.</td>\n        </tr>\n        <tr>\n            <td><h5>sink.clustering.sort-in-cluster</h5></td>\n            <td style="word-wrap: break-word;">true</td>\n            <td>Boolean</td>\n            <td>Indicates whether to further sort data belonged to each sink task after range partitioning.</td>\n        </tr>\n        <tr>\n            <td><h5>sink.committer-cpu</h5></td>\n            <td style="word-wrap: break-word;">1.0</td>\n            <td>Double</td>\n            <td>Sink committer cpu to control cpu cores of global committer.</td>\n        </tr>\n        <tr>\n            <td><h5>sink.committer-memory</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>MemorySize</td>\n            <td>Sink committer memory to control heap memory of global committer.</td>\n        </tr>\n        <tr>\n            <td><h5>sink.committer-operator-chaining</h5></td>\n            <td style="word-wrap: break-word;">true</td>\n            <td>Boolean</td>\n            <td>Allow sink committer and writer operator to be chained together</td>\n        </tr>\n        <tr>\n            <td><h5>sink.coordinator-commit.enabled</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>If true, run the Paimon committer inside the Flink JobManager via an OperatorCoordinator. This decouples commit from any single TaskManager subtask so that region failover does not have to restart the whole pipeline. Only supports unaware-bucket append tables in streaming mode with checkpointing enabled; unsupported configurations fail during sink planning.</td>\n        </tr>\n        <tr>\n            <td><h5>sink.cross-partition.managed-memory</h5></td>\n            <td style="word-wrap: break-word;">256 mb</td>\n            <td>MemorySize</td>\n            <td>Weight of managed memory for RocksDB in cross-partition update, Flink will compute the memory size according to the weight, the actual memory used depends on the running environment.</td>\n        </tr>\n        <tr>\n            <td><h5>sink.key-only-deletes.enabled</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>If true, a primary-key table sink advertises the key-only (partial) deletes capability, allowing the Flink planner to drop the upstream ChangelogNormalize node when the source produces deletes by key. Requires Flink 2.1+; no effect on Flink 1.x or 2.0. Does not apply when the table has no primary key, when \'changelog-producer\' is \'input\', or when \'merge-engine\' is \'aggregation\' or \'partial-update\' with aggregation functions; in those cases a warning is logged. Disabled by default.</td>\n        </tr>\n        <tr>\n            <td><h5>sink.managed.writer-buffer-memory</h5></td>\n            <td style="word-wrap: break-word;">256 mb</td>\n            <td>MemorySize</td>\n            <td>Weight of writer buffer in managed memory, Flink will compute the memory size for writer according to the weight, the actual memory used depends on the running environment.</td>\n        </tr>\n        <tr>\n            <td><h5>sink.operator-uid.suffix</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>Set the uid suffix for the writer, dynamic bucket assigner and committer operators. The uid format is ${UID_PREFIX}_${TABLE_NAME}_${USER_UID_SUFFIX}. If the uid suffix is not set, flink will automatically generate the operator uid, which may be incompatible when the topology changes.</td>\n        </tr>\n        <tr>\n            <td><h5>sink.parallelism</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Integer</td>\n            <td>Defines a custom parallelism for the sink. By default, if this option is not defined, the planner will derive the parallelism for each statement individually by also considering the global configuration.</td>\n        </tr>\n        <tr>\n            <td><h5>sink.savepoint.auto-tag</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>If true, a tag will be automatically created for the snapshot created by flink savepoint.</td>\n        </tr>\n        <tr>\n            <td><h5>sink.use-managed-memory-allocator</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>If true, flink sink will use managed memory for merge tree; otherwise, it will create an independent memory allocator.</td>\n        </tr>\n        <tr>\n            <td><h5>sink.writer-coordinator.cache-expire-after-access</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Duration</td>\n            <td>Optional idle TTL for writer coordinator manifest cache entries. Disabled by default. When set, an entry that has not been accessed within this duration is evicted, releasing its heap. The cache stays bounded by \'sink.writer-coordinator.cache-memory\' regardless of this setting.</td>\n        </tr>\n        <tr>\n            <td><h5>sink.writer-coordinator.cache-memory</h5></td>\n            <td style="word-wrap: break-word;">2 gb</td>\n            <td>MemorySize</td>\n            <td>Controls the cache memory of writer coordinator to cache manifest files in Job Manager.</td>\n        </tr>\n        <tr>\n            <td><h5>sink.writer-coordinator.cache-soft-values</h5></td>\n            <td style="word-wrap: break-word;">true</td>\n            <td>Boolean</td>\n            <td>If true (default), writer coordinator manifest cache entries are held with soft references and may be reclaimed by the GC under memory pressure. This can trigger a cache-thrash spiral where reclaimed entries are refetched, spiking heap and forcing further reclamation. Set to false to hold entries with strong references, breaking the spiral; the cache then stays bounded by weight up to \'sink.writer-coordinator.cache-memory\' (size the Job Manager total heap memory to at least roughly twice that value).</td>\n        </tr>\n        <tr>\n            <td><h5>sink.writer-coordinator.enabled</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Enable sink writer coordinator to plan data files in Job Manager.</td>\n        </tr>\n        <tr>\n            <td><h5>sink.writer-coordinator.page-size</h5></td>\n            <td style="word-wrap: break-word;">32 kb</td>\n            <td>MemorySize</td>\n            <td>Controls the page size for one RPC request of writer coordinator.</td>\n        </tr>\n        <tr>\n            <td><h5>sink.writer-coordinator.prefetch-manifests</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>If true, the writer coordinator eagerly reads all data manifests of the latest snapshot during refresh to warm the in-Job-Manager manifest cache. This avoids many concurrent cold manifest reads when high-parallelism writers restore at the same time, reducing Job Manager heap pressure at the cost of one full manifest read per refresh.</td>\n        </tr>\n        <tr>\n            <td><h5>sink.writer-cpu</h5></td>\n            <td style="word-wrap: break-word;">1.0</td>\n            <td>Double</td>\n            <td>Sink writer cpu to control cpu cores of writer.</td>\n        </tr>\n        <tr>\n            <td><h5>sink.writer-memory</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>MemorySize</td>\n            <td>Sink writer memory to control heap memory of writer.</td>\n        </tr>\n        <tr>\n            <td><h5>sink.writer-refresh-detectors</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>The option groups which are expected to be refreshed when streaming writing, multiple option group separated by commas. Now only \'external-paths\' is supported.</td>\n        </tr>\n        <tr>\n            <td><h5>source.checkpoint-align.enabled</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether to align the flink checkpoint with the snapshot of the paimon table, If true, a checkpoint will only be made if a snapshot is consumed.</td>\n        </tr>\n        <tr>\n            <td><h5>source.checkpoint-align.timeout</h5></td>\n            <td style="word-wrap: break-word;">30 s</td>\n            <td>Duration</td>\n            <td>If the new snapshot has not been generated when the checkpoint starts to trigger, the enumerator will block the checkpoint and wait for the new snapshot. Set the maximum waiting time to avoid infinite waiting, if timeout, the checkpoint will fail. Note that it should be set smaller than the checkpoint timeout.</td>\n        </tr>\n        <tr>\n            <td><h5>source.operator-uid.suffix</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>String</td>\n            <td>Set the uid suffix for the source operators. After setting, the uid format is ${UID_PREFIX}_${TABLE_NAME}_${USER_UID_SUFFIX}. If the uid suffix is not set, flink will automatically generate the operator uid, which may be incompatible when the topology changes.</td>\n        </tr>\n        <tr>\n            <td><h5>unaware-bucket.compaction.parallelism</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Integer</td>\n            <td>Defines a custom parallelism for the unaware-bucket table compaction job. By default, if this option is not defined, the planner will derive the parallelism for each statement individually by also considering the global configuration.</td>\n        </tr>\n        <tr>\n            <td><h5>unaware-bucket.no-shuffle</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>If true, the CDC sync pipeline will skip the network shuffle between source and writer operators. This is only supported for bucket-unaware (append) tables where each writer subtask independently appends data without bucket ownership constraints. This eliminates data transfer overhead when the source already provides suitable data distribution (e.g., Kafka partitions).</td>\n        </tr>\n    </tbody>\n</table>\n'}),"\n",(0,d.jsx)(e.h3,{id:"sparkcatalogoptions",children:"SparkCatalogOptions"}),"\n",(0,d.jsx)(e.p,{children:"Spark catalog options for paimon."}),"\n",(0,d.jsx)(o.A,{html:'\x3c!--\nLicensed to the Apache Software Foundation (ASF) under one\nor more contributor license agreements.  See the NOTICE file\ndistributed with this work for additional information\nregarding copyright ownership.  The ASF licenses this file\nto you under the Apache License, Version 2.0 (the\n"License"); you may not use this file except in compliance\nwith the License.  You may obtain a copy of the License at\n\n  http://www.apache.org/licenses/LICENSE-2.0\n\nUnless required by applicable law or agreed to in writing,\nsoftware distributed under the License is distributed on an\n"AS IS" BASIS, WITHOUT WARRANTIES OR CONDITIONS OF ANY\nKIND, either express or implied.  See the License for the\nspecific language governing permissions and limitations\nunder the License.\n--\x3e\n<table class="configuration table table-bordered">\n    <thead>\n        <tr>\n            <th class="text-left" style="width: 20%">Key</th>\n            <th class="text-left" style="width: 15%">Default</th>\n            <th class="text-left" style="width: 10%">Type</th>\n            <th class="text-left" style="width: 55%">Description</th>\n        </tr>\n    </thead>\n    <tbody>\n        <tr>\n            <td><h5>catalog.create-underlying-session-catalog</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>If true, create and use an underlying session catalog instead of default session catalog when use SparkGenericCatalog.</td>\n        </tr>\n        <tr>\n            <td><h5>defaultDatabase</h5></td>\n            <td style="word-wrap: break-word;">"default"</td>\n            <td>String</td>\n            <td>The default database name.</td>\n        </tr>\n        <tr>\n            <td><h5>v1Function.enabled</h5></td>\n            <td style="word-wrap: break-word;">true</td>\n            <td>Boolean</td>\n            <td>Whether to enable v1 function.</td>\n        </tr>\n    </tbody>\n</table>\n'}),"\n",(0,d.jsx)(e.h3,{id:"sparkconnectoroptions",children:"SparkConnectorOptions"}),"\n",(0,d.jsx)(e.p,{children:"Spark connector options for paimon."}),"\n",(0,d.jsx)(o.A,{html:'\x3c!--\nLicensed to the Apache Software Foundation (ASF) under one\nor more contributor license agreements.  See the NOTICE file\ndistributed with this work for additional information\nregarding copyright ownership.  The ASF licenses this file\nto you under the Apache License, Version 2.0 (the\n"License"); you may not use this file except in compliance\nwith the License.  You may obtain a copy of the License at\n\n  http://www.apache.org/licenses/LICENSE-2.0\n\nUnless required by applicable law or agreed to in writing,\nsoftware distributed under the License is distributed on an\n"AS IS" BASIS, WITHOUT WARRANTIES OR CONDITIONS OF ANY\nKIND, either express or implied.  See the License for the\nspecific language governing permissions and limitations\nunder the License.\n--\x3e\n<table class="configuration table table-bordered">\n    <thead>\n        <tr>\n            <th class="text-left" style="width: 20%">Key</th>\n            <th class="text-left" style="width: 15%">Default</th>\n            <th class="text-left" style="width: 10%">Type</th>\n            <th class="text-left" style="width: 55%">Description</th>\n        </tr>\n    </thead>\n    <tbody>\n        <tr>\n            <td><h5>legacy-timestamp-mapping.enabled</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>If true, map Paimon TIMESTAMP to Spark TIMESTAMP instead of TIMESTAMP_NTZ.</td>\n        </tr>\n        <tr>\n            <td><h5>read.allow.fullScan</h5></td>\n            <td style="word-wrap: break-word;">true</td>\n            <td>Boolean</td>\n            <td>Whether to allow full scan when reading a partitioned table.</td>\n        </tr>\n        <tr>\n            <td><h5>read.changelog</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether to read row in the form of changelog (add rowkind column in row to represent its change type).</td>\n        </tr>\n        <tr>\n            <td><h5>read.stream.maxBytesPerTrigger</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Long</td>\n            <td>The maximum number of bytes returned in a single batch.</td>\n        </tr>\n        <tr>\n            <td><h5>read.stream.maxFilesPerTrigger</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Integer</td>\n            <td>The maximum number of files returned in a single batch.</td>\n        </tr>\n        <tr>\n            <td><h5>read.stream.maxRowsPerTrigger</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Long</td>\n            <td>The maximum number of rows returned in a single batch.</td>\n        </tr>\n        <tr>\n            <td><h5>read.stream.maxTriggerDelayMs</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Long</td>\n            <td>The maximum delay between two adjacent batches, which used to create MinRowsReadLimit with read.stream.minRowsPerTrigger together.</td>\n        </tr>\n        <tr>\n            <td><h5>read.stream.minRowsPerTrigger</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Long</td>\n            <td>The minimum number of rows returned in a single batch, which used to create MinRowsReadLimit with read.stream.maxTriggerDelayMs together.</td>\n        </tr>\n        <tr>\n            <td><h5>requiredSparkConfsCheck.enabled</h5></td>\n            <td style="word-wrap: break-word;">true</td>\n            <td>Boolean</td>\n            <td>Whether to verify SparkSession is initialized with required configurations.</td>\n        </tr>\n        <tr>\n            <td><h5>source.split.target-size-with-column-pruning</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Whether to adjust the target split size based on pruned (projected) columns. If enabled, split size estimation uses only the columns actually being read.</td>\n        </tr>\n        <tr>\n            <td><h5>write.data-evolution.update-conflict-retry.max-attempts</h5></td>\n            <td style="word-wrap: break-word;">20</td>\n            <td>Integer</td>\n            <td>Maximum attempts for Spark V1 UPDATE on data-evolution tables when concurrent partial-column updates conflict on the same row-id range and update columns. Values less than 2 disable retry.</td>\n        </tr>\n        <tr>\n            <td><h5>write.data-evolution.update-conflict-retry.wait-ms</h5></td>\n            <td style="word-wrap: break-word;">10</td>\n            <td>Long</td>\n            <td>Wait time in milliseconds between retry attempts for Spark V1 UPDATE on data-evolution tables after row-id range update conflicts.</td>\n        </tr>\n        <tr>\n            <td><h5>write.merge-schema</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>If true, evolve the table schema to accept new columns from the incoming data. Existing column types are preserved and incoming values are cast to them; to also widen existing types, enable \'write.merge-schema.type-widening\'.</td>\n        </tr>\n        <tr>\n            <td><h5>write.merge-schema.explicit-cast</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Only effective when \'write.merge-schema.type-widening\' is true. If true, also allow lossy type changes between compatible types (e.g. BIGINT -&gt; INT, STRING -&gt; DATE).</td>\n        </tr>\n        <tr>\n            <td><h5>write.merge-schema.type-widening</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>Only effective when \'write.merge-schema\' is true. If true, widen an existing column type when the incoming data has a wider compatible type (e.g. INT -&gt; BIGINT, DECIMAL precision increase). Lossy changes are still rejected unless \'write.merge-schema.explicit-cast\' is also true.</td>\n        </tr>\n        <tr>\n            <td><h5>write.use-v2-write</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>If true, v2 write will be used. Currently, only HASH_FIXED and BUCKET_UNAWARE bucket modes are supported. Will fall back to v1 write for other bucket modes. Currently, Spark V2 write does not support TableCapability.STREAMING_WRITE.</td>\n        </tr>\n    </tbody>\n</table>\n'}),"\n",(0,d.jsx)(e.h3,{id:"orc-options",children:"ORC Options"}),"\n",(0,d.jsx)(o.A,{html:'\x3c!--\nLicensed to the Apache Software Foundation (ASF) under one\nor more contributor license agreements.  See the NOTICE file\ndistributed with this work for additional information\nregarding copyright ownership.  The ASF licenses this file\nto you under the Apache License, Version 2.0 (the\n"License"); you may not use this file except in compliance\nwith the License.  You may obtain a copy of the License at\n\n  http://www.apache.org/licenses/LICENSE-2.0\n\nUnless required by applicable law or agreed to in writing,\nsoftware distributed under the License is distributed on an\n"AS IS" BASIS, WITHOUT WARRANTIES OR CONDITIONS OF ANY\nKIND, either express or implied.  See the License for the\nspecific language governing permissions and limitations\nunder the License.\n--\x3e\n<table class="configuration table table-bordered">\n    <thead>\n        <tr>\n            <th class="text-left" style="width: 20%">Key</th>\n            <th class="text-left" style="width: 15%">Default</th>\n            <th class="text-left" style="width: 10%">Type</th>\n            <th class="text-left" style="width: 55%">Description</th>\n        </tr>\n    </thead>\n    <tbody>\n        <tr>\n            <td><h5>orc.column.encoding.direct</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Integer</td>\n            <td>Comma-separated list of fields for which dictionary encoding is to be skipped in orc.</td>\n        </tr>\n        <tr>\n            <td><h5>orc.dictionary.key.threshold</h5></td>\n            <td style="word-wrap: break-word;">0.8</td>\n            <td>Double</td>\n            <td>If the number of distinct keys in a dictionary is greater than this fraction of the total number of non-null rows, turn off dictionary encoding in orc. Use 0 to always disable dictionary encoding. Use 1 to always use dictionary encoding.</td>\n        </tr>\n        <tr>\n            <td><h5>orc.timestamp-ltz.legacy.type</h5></td>\n            <td style="word-wrap: break-word;">true</td>\n            <td>Boolean</td>\n            <td>This option is used to be compatible with the paimon-orc\'s old behavior for the `timestamp_ltz` data type.</td>\n        </tr>\n    </tbody>\n</table>\n'}),"\n",(0,d.jsx)(e.h3,{id:"rocksdb-options",children:"RocksDB Options"}),"\n",(0,d.jsx)(e.p,{children:"The following options allow users to finely adjust RocksDB for better performance. You can either specify them in table properties or in dynamic table hints."}),"\n",(0,d.jsx)(o.A,{html:'\x3c!--\nLicensed to the Apache Software Foundation (ASF) under one\nor more contributor license agreements.  See the NOTICE file\ndistributed with this work for additional information\nregarding copyright ownership.  The ASF licenses this file\nto you under the Apache License, Version 2.0 (the\n"License"); you may not use this file except in compliance\nwith the License.  You may obtain a copy of the License at\n\n  http://www.apache.org/licenses/LICENSE-2.0\n\nUnless required by applicable law or agreed to in writing,\nsoftware distributed under the License is distributed on an\n"AS IS" BASIS, WITHOUT WARRANTIES OR CONDITIONS OF ANY\nKIND, either express or implied.  See the License for the\nspecific language governing permissions and limitations\nunder the License.\n--\x3e\n<table class="configuration table table-bordered">\n    <thead>\n        <tr>\n            <th class="text-left" style="width: 20%">Key</th>\n            <th class="text-left" style="width: 15%">Default</th>\n            <th class="text-left" style="width: 10%">Type</th>\n            <th class="text-left" style="width: 55%">Description</th>\n        </tr>\n    </thead>\n    <tbody>\n        <tr>\n            <td><h5>lookup.cache-rows</h5></td>\n            <td style="word-wrap: break-word;">10000</td>\n            <td>Long</td>\n            <td>The maximum number of rows to store in the cache.</td>\n        </tr>\n        <tr>\n            <td><h5>lookup.continuous.discovery-interval</h5></td>\n            <td style="word-wrap: break-word;">(none)</td>\n            <td>Duration</td>\n            <td>The discovery interval of lookup continuous reading. This is used as an SQL hint. If it\'s not configured, the lookup function will fallback to \'continuous.discovery-interval\'.</td>\n        </tr>\n        <tr>\n            <td><h5>rocksdb.block.blocksize</h5></td>\n            <td style="word-wrap: break-word;">4 kb</td>\n            <td>MemorySize</td>\n            <td>The approximate size (in bytes) of user data packed per block. The default blocksize is \'4KB\'.</td>\n        </tr>\n        <tr>\n            <td><h5>rocksdb.block.cache-size</h5></td>\n            <td style="word-wrap: break-word;">128 mb</td>\n            <td>MemorySize</td>\n            <td>The amount of the cache for data blocks in RocksDB.</td>\n        </tr>\n        <tr>\n            <td><h5>rocksdb.block.metadata-blocksize</h5></td>\n            <td style="word-wrap: break-word;">4 kb</td>\n            <td>MemorySize</td>\n            <td>Approximate size of partitioned metadata packed per block. Currently applied to indexes block when partitioned index/filters option is enabled. The default blocksize is \'4KB\'.</td>\n        </tr>\n        <tr>\n            <td><h5>rocksdb.bloom-filter.bits-per-key</h5></td>\n            <td style="word-wrap: break-word;">10.0</td>\n            <td>Double</td>\n            <td>Bits per key that bloom filter will use, this only take effect when bloom filter is used. The default value is 10.0.</td>\n        </tr>\n        <tr>\n            <td><h5>rocksdb.bloom-filter.block-based-mode</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>If true, RocksDB will use block-based filter instead of full filter, this only take effect when bloom filter is used. The default value is \'false\'.</td>\n        </tr>\n        <tr>\n            <td><h5>rocksdb.compaction.level.max-size-level-base</h5></td>\n            <td style="word-wrap: break-word;">256 mb</td>\n            <td>MemorySize</td>\n            <td>The upper-bound of the total size of level base files in bytes. The default value is \'256MB\'.</td>\n        </tr>\n        <tr>\n            <td><h5>rocksdb.compaction.level.target-file-size-base</h5></td>\n            <td style="word-wrap: break-word;">64 mb</td>\n            <td>MemorySize</td>\n            <td>The target file size for compaction, which determines a level-1 file size. The default value is \'64MB\'.</td>\n        </tr>\n        <tr>\n            <td><h5>rocksdb.compaction.level.use-dynamic-size</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>If true, RocksDB will pick target size of each level dynamically. From an empty DB, RocksDB would make last level the base level, which means merging L0 data into the last level, until it exceeds max_bytes_for_level_base. And then repeat this process for second last level and so on. The default value is \'false\'. For more information, please refer to <a href="https://github.com/facebook/rocksdb/wiki/Leveled-Compaction#level_compaction_dynamic_level_bytes-is-true">RocksDB\'s doc.</a></td>\n        </tr>\n        <tr>\n            <td><h5>rocksdb.compaction.style</h5></td>\n            <td style="word-wrap: break-word;">LEVEL</td>\n            <td><p>Enum</p></td>\n            <td>The specified compaction style for DB. Candidate compaction style is LEVEL, FIFO, UNIVERSAL or NONE, and Flink chooses \'LEVEL\' as default style.<br /><br />Possible values:<ul><li>"LEVEL"</li><li>"UNIVERSAL"</li><li>"FIFO"</li><li>"NONE"</li></ul></td>\n        </tr>\n        <tr>\n            <td><h5>rocksdb.compression.type</h5></td>\n            <td style="word-wrap: break-word;">LZ4_COMPRESSION</td>\n            <td><p>Enum</p></td>\n            <td>The compression type.<br /><br />Possible values:<ul><li>"NO_COMPRESSION"</li><li>"SNAPPY_COMPRESSION"</li><li>"ZLIB_COMPRESSION"</li><li>"BZLIB2_COMPRESSION"</li><li>"LZ4_COMPRESSION"</li><li>"LZ4HC_COMPRESSION"</li><li>"XPRESS_COMPRESSION"</li><li>"ZSTD_COMPRESSION"</li><li>"DISABLE_COMPRESSION_OPTION"</li></ul></td>\n        </tr>\n        <tr>\n            <td><h5>rocksdb.files.open</h5></td>\n            <td style="word-wrap: break-word;">-1</td>\n            <td>Integer</td>\n            <td>The maximum number of open files (per stateful operator) that can be used by the DB, \'-1\' means no limit. The default value is \'-1\'.</td>\n        </tr>\n        <tr>\n            <td><h5>rocksdb.thread.num</h5></td>\n            <td style="word-wrap: break-word;">2</td>\n            <td>Integer</td>\n            <td>The maximum number of concurrent background flush and compaction jobs (per stateful operator). The default value is \'2\'.</td>\n        </tr>\n        <tr>\n            <td><h5>rocksdb.use-bloom-filter</h5></td>\n            <td style="word-wrap: break-word;">false</td>\n            <td>Boolean</td>\n            <td>If true, every newly created SST file will contain a Bloom filter. It is disabled by default.</td>\n        </tr>\n        <tr>\n            <td><h5>rocksdb.writebuffer.count</h5></td>\n            <td style="word-wrap: break-word;">2</td>\n            <td>Integer</td>\n            <td>The maximum number of write buffers that are built up in memory. The default value is \'2\'.</td>\n        </tr>\n        <tr>\n            <td><h5>rocksdb.writebuffer.number-to-merge</h5></td>\n            <td style="word-wrap: break-word;">1</td>\n            <td>Integer</td>\n            <td>The minimum number of write buffers that will be merged together before writing to storage. The default value is \'1\'.</td>\n        </tr>\n        <tr>\n            <td><h5>rocksdb.writebuffer.size</h5></td>\n            <td style="word-wrap: break-word;">64 mb</td>\n            <td>MemorySize</td>\n            <td>The amount of data built up in memory (backed by an unsorted log on disk) before converting to a sorted on-disk files. The default writebuffer size is \'64MB\'.</td>\n        </tr>\n    </tbody>\n</table>\n'})]})}function p(t={}){const{wrapper:e}={...(0,a.R)(),...t.components};return e?(0,d.jsx)(e,{...t,children:(0,d.jsx)(c,{...t})}):c(t)}},6678(t,e,n){n.d(e,{A:()=>d});n(6540);var r=n(4848);function d({html:t}){return(0,r.jsx)("div",{className:"config-table-wrapper",dangerouslySetInnerHTML:{__html:t}})}},8453(t,e,n){n.d(e,{R:()=>o,x:()=>i});var r=n(6540);const d={},a=r.createContext(d);function o(t){const e=r.useContext(a);return r.useMemo(function(){return"function"==typeof t?t(e):{...e,...t}},[e,t])}function i(t){let e;return e=t.disableParentContext?"function"==typeof t.components?t.components(d):t.components||d:o(t.components),r.createElement(a.Provider,{value:e},t.children)}}}]);